#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include "../common.h"

long long get_time(void);

static void
findK_omp(long height,
          knode *knodesD,
          long knodes_elem,
          record *recordsD,
          long *currKnodeD,
          long *offsetD,
          int *keysD,
          record *ansD,
          int count,
          int threadsPerBlock)
{
	int bid;

	#pragma omp parallel for schedule(static)
	for (bid = 0; bid < count; bid++) {
		long curr = currKnodeD[bid];
		long off = offsetD[bid];
		long i;

		for (i = 0; i < height; i++) {
			long base_curr = curr;
			long base_off = off;
			long new_off = off;
			int thid;

			for (thid = 0; thid < threadsPerBlock; thid++) {
				if ((knodesD[base_curr].keys[thid] <= keysD[bid]) &&
				    (knodesD[base_curr].keys[thid + 1] > keysD[bid])) {
					if (knodesD[base_off].indices[thid] < knodes_elem) {
						new_off = knodesD[base_off].indices[thid];
					}
				}
			}

			off = new_off;
			curr = off;
		}

		for (int thid = 0; thid < threadsPerBlock; thid++) {
			if (knodesD[curr].keys[thid] == keysD[bid]) {
				ansD[bid].value = recordsD[knodesD[curr].indices[thid]].value;
			}
		}

		currKnodeD[bid] = curr;
		offsetD[bid] = off;
	}
}

void
kernel_gpu_cuda_wrapper(record *records,
						long records_mem,
						knode *knodes,
						long knodes_elem,
						long knodes_mem,

						int order,
						long maxheight,
						int count,

						long *currKnode,
						long *offset,
						int *keys,
						record *ans)
{
	long long time0;
	long long time1;
	long long time2;
	long long time3;
	long long time4;
	long long time5;
	long long time6;

	time0 = get_time();

	int numBlocks;
	numBlocks = count;
	int threadsPerBlock;
	threadsPerBlock = order < 1024 ? order : 1024;

	printf("# of blocks = %d, # of threads/block = %d (ensure that device can handle)\n", numBlocks, threadsPerBlock);

	time1 = get_time();

	record *recordsD = (record *)malloc(records_mem);
	knode *knodesD = (knode *)malloc(knodes_mem);
	long *currKnodeD = (long *)malloc(count * sizeof(long));
	long *offsetD = (long *)malloc(count * sizeof(long));
	int *keysD = (int *)malloc(count * sizeof(int));
	record *ansD = (record *)malloc(count * sizeof(record));

	time2 = get_time();

	memcpy(recordsD, records, records_mem);
	memcpy(knodesD, knodes, knodes_mem);
	memcpy(currKnodeD, currKnode, count * sizeof(long));
	memcpy(offsetD, offset, count * sizeof(long));
	memcpy(keysD, keys, count * sizeof(int));
	memcpy(ansD, ans, count * sizeof(record));

	time3 = get_time();

	findK_omp(maxheight,
			  knodesD,
			  knodes_elem,
			  recordsD,
			  currKnodeD,
			  offsetD,
			  keysD,
			  ansD,
			  count,
			  threadsPerBlock);

	time4 = get_time();

	memcpy(ans, ansD, count * sizeof(record));

	time5 = get_time();

	free(recordsD);
	free(knodesD);
	free(currKnodeD);
	free(offsetD);
	free(keysD);
	free(ansD);

	time6 = get_time();

	printf("Time spent in different stages of GPU_CUDA KERNEL:\n");

	printf("%15.12f s, %15.12f % : GPU: SET DEVICE / DRIVER INIT\n",	(float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f % : GPU MEM: ALO\n", 					(float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f % : GPU MEM: COPY IN\n",					(float) (time3-time2) / 1000000, (float) (time3-time2) / (float) (time6-time0) * 100);

	printf("%15.12f s, %15.12f % : GPU: KERNEL\n",						(float) (time4-time3) / 1000000, (float) (time4-time3) / (float) (time6-time0) * 100);

	printf("%15.12f s, %15.12f % : GPU MEM: COPY OUT\n",				(float) (time5-time4) / 1000000, (float) (time5-time4) / (float) (time6-time0) * 100);
	printf("%15.12f s, %15.12f % : GPU MEM: FRE\n", 					(float) (time6-time5) / 1000000, (float) (time6-time5) / (float) (time6-time0) * 100);

	printf("Total time:\n");
	printf("%.12f s\n", 												(float) (time6-time0) / 1000000);
}

#ifdef __cplusplus
}
#endif

