static float *alloc_1d_dbl(int n)
{
  float *newp;

  newp = (float *) malloc((unsigned) (n * sizeof(float)));
  if (newp == NULL) {
    printf("ALLOC_1D_DBL: Couldn't allocate array of floats\n");
    return NULL;
  }
  return newp;
}

float **alloc_2d_dbl(int m, int n)
{
  int i;
  float **newp;

  newp = (float **) malloc((unsigned) (m * sizeof(float *)));
  if (newp == NULL) {
    printf("ALLOC_2D_DBL: Couldn't allocate array of dbl ptrs\n");
    return NULL;
  }

  for (i = 0; i < m; i++) {
    newp[i] = alloc_1d_dbl(n);
  }

  return newp;
}

static void bpnn_randomize_weights(float **w, int m, int n)
{
  int i, j;

  for (i = 0; i <= m; i++) {
    for (j = 0; j <= n; j++) {
      w[i][j] = (float) rand() / RAND_MAX;
    }
  }
}

static void bpnn_randomize_row(float *w, int m)
{
  int i;

  for (i = 0; i <= m; i++) {
    w[i] = 0.1f;
  }
}

static void bpnn_zero_weights(float **w, int m, int n)
{
  int i, j;

  for (i = 0; i <= m; i++) {
