    delta_h[j] = h * (1.0f - h) * sum;
    errsum += ABS(delta_h[j]);
  }
  *err = errsum;
}

void bpnn_adjust_weights(float *delta, int ndelta, float *ly, int nly, float **w, float **oldw)
{
  int j, k;

  ly[0] = 1.0f;

  omp_set_num_threads(NUM_THREAD);
#pragma omp parallel for private(j, k) schedule(static)
  for (j = 1; j <= ndelta; j++) {
    for (k = 0; k <= nly; k++) {
      float new_dw;

      new_dw = ((ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[k][j]));
      w[k][j] += new_dw;
      oldw[k][j] = new_dw;
    }
  }
}

void bpnn_feedforward(BPNN *net)
{
  int in, hid, out;

  in = net->input_n;
  hid = net->hidden_n;
  out = net->output_n;

  bpnn_layerforward(net->input_units, net->hidden_units, net->input_weights, in, hid);
  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
}

void bpnn_train(BPNN *net, float *eo, float *eh)
{
  int in, hid, out;
  float out_err, hid_err;

  in = net->input_n;
  hid = net->hidden_n;
  out = net->output_n;

  bpnn_layerforward(net->input_units, net->hidden_units, net->input_weights, in, hid);
  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);

  bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);
  bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out,
                    net->hidden_weights, net->hidden_units, &hid_err);
  *eo = out_err;
  *eh = hid_err;

  bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid,
                      net->hidden_weights, net->hidden_prev_weights);
  bpnn_adjust_weights(net->hidden_delta, hid, net->input_units, in,
                      net->input_weights, net->input_prev_weights);
}

void bpnn_train_cuda(BPNN *net, float *eo, float *eh)
{
  int in, hid, out;
  float out_err, hid_err;
  int m;
  float *partial_sum;
  float *input_weights_one_dim;
  float *input_weights_prev_one_dim;
  int num_blocks;

  (void) eo;
  (void) eh;

  in = net->input_n;
  hid = net->hidden_n;
  out = net->output_n;

  printf("Performing GPU computation\n");

  num_blocks = in / HEIGHT;

  input_weights_one_dim = (float *) malloc((in + 1) * (hid + 1) * sizeof(float));
  input_weights_prev_one_dim = (float *) malloc((in + 1) * (hid + 1) * sizeof(float));
  partial_sum = (float *) malloc((num_blocks > 0 ? num_blocks : 1) * (hid > 0 ? hid : 1) * sizeof(float));

  m = 0;
  {
    int k, j;
    for (k = 0; k <= in; k++) {
      for (j = 0; j <= hid; j++) {
        input_weights_one_dim[m] = net->input_weights[k][j];
        input_weights_prev_one_dim[m] = net->input_prev_weights[k][j];
        m++;
      }
    }
  }

  if (num_blocks > 0) {
    int by;

    omp_set_num_threads(NUM_THREAD);
#pragma omp parallel for private(by) schedule(static)
    for (by = 0; by < num_blocks; by++) {
      int tx;
      for (tx = 0; tx < hid; tx++) {
        float sum;
        int ty;

        sum = 0.0f;
        for (ty = 0; ty < HEIGHT; ty++) {
          int row;

          row = HEIGHT * by + ty + 1;
          if (row <= in) {
            sum += net->input_weights[row][tx + 1] * net->input_units[row];
          }
        }
        partial_sum[by * hid + tx] = sum;
      }
    }
  }

  {
    int j;
    for (j = 1; j <= hid; j++) {
      float sum;
      int k;

      sum = 0.0f;
      for (k = 0; k < num_blocks; k++) {
        sum += partial_sum[k * hid + (j - 1)];
      }
      sum += net->input_weights[0][j];
      net->hidden_units[j] = (float) (1.0 / (1.0 + exp(-sum)));
    }
  }

  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
  bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);
  bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out,
                    net->hidden_weights, net->hidden_units, &hid_err);
  bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid,
                      net->hidden_weights, net->hidden_prev_weights);

  if (num_blocks > 0) {
    int by;

    omp_set_num_threads(NUM_THREAD);
#pragma omp parallel for private(by) schedule(static)
    for (by = 0; by < num_blocks; by++) {
      int ty;
      for (ty = 0; ty < HEIGHT; ty++) {
        int row;
        row = HEIGHT * by + ty + 1;
        if (row <= in) {
          int tx;
          for (tx = 1; tx <= hid; tx++) {
            int index;
            float new_dw;

            index = row * (hid + 1) + tx;
            new_dw = ((ETA * net->hidden_delta[tx] * net->input_units[row]) +
                      (MOMENTUM * input_weights_prev_one_dim[index]));
            input_weights_one_dim[index] += new_dw;
            input_weights_prev_one_dim[index] = new_dw;
          }
        }
      }
    }
  }

  {
    int tx;
    for (tx = 1; tx <= hid; tx++) {
      float new_dw;

      new_dw = ((ETA * net->hidden_delta[tx]) +
                (MOMENTUM * input_weights_prev_one_dim[tx]));
      input_weights_one_dim[tx] += new_dw;
      input_weights_prev_one_dim[tx] = new_dw;
    }
  }

  free(partial_sum);
  free(input_weights_one_dim);
  free(input_weights_prev_one_dim);

  (void) out_err;
  (void) hid_err;
}

