struct Node
{
	int starting;
	int no_of_edges;
};

static void Kernel(Node* g_graph_nodes, int* g_graph_edges, bool* g_graph_mask,
                   bool* g_updating_graph_mask, bool *g_graph_visited,
                   int* g_cost, int no_of_nodes)
{
	#pragma omp parallel for schedule(static)
	for (int tid = 0; tid < no_of_nodes; tid++)
	{
		if (g_graph_mask[tid])
		{
			g_graph_mask[tid] = false;
			for (int i = g_graph_nodes[tid].starting;
			     i < (g_graph_nodes[tid].no_of_edges + g_graph_nodes[tid].starting);
			     i++)
			{
				int id = g_graph_edges[i];
				if (!g_graph_visited[id])
				{
					#pragma omp critical(bfs_update_neighbor)
					{
						if (!g_graph_visited[id] && !g_updating_graph_mask[id])
						{
							g_cost[id] = g_cost[tid] + 1;
							g_updating_graph_mask[id] = true;
						}
					}
				}
			}
		}
	}
}

static void Kernel2(bool* g_graph_mask, bool *g_updating_graph_mask,
                    bool* g_graph_visited, bool *g_over, int no_of_nodes)
{
	int over_int = 0;

	#pragma omp parallel for reduction(|:over_int) schedule(static)
	for (int tid = 0; tid < no_of_nodes; tid++)
	{
		if (g_updating_graph_mask[tid])
		{
			g_graph_mask[tid] = true;
			g_graph_visited[tid] = true;
			over_int = 1;
			g_updating_graph_mask[tid] = false;
		}
	}

	*g_over = (over_int != 0);
}

