#define IN_RANGE(x, min, max) ((x) >= (min) && (x) <= (max))
#define CLAMP_RANGE(x, min, max) x = (x < (min)) ? (min) : ((x > (max)) ? (max) : (x))
#define MIN(a, b) ((a) <= (b) ? (a) : (b))

static void calculate_temp_step(float *power,
                                float *temp_src,
                                float *temp_dst,
                                int grid_cols,
                                int grid_rows,
                                float Cap,
                                float Rx,
                                float Ry,
                                float Rz,
                                float step)
{
    float step_div_Cap = step / Cap;
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;
    float local_amb_temp = 80.0f;

    #pragma omp parallel for collapse(2) schedule(static)
    for (int r = 0; r < grid_rows; r++) {
        for (int c = 0; c < grid_cols; c++) {
            int idx = r * grid_cols + c;

            int n = (r == 0) ? idx : idx - grid_cols;
            int s = (r == grid_rows - 1) ? idx : idx + grid_cols;
            int w = (c == 0) ? idx : idx - 1;
            int e = (c == grid_cols - 1) ? idx : idx + 1;

            temp_dst[idx] = temp_src[idx] + step_div_Cap * (
                power[idx] +
                (temp_src[s] + temp_src[n] - 2.0f * temp_src[idx]) * Ry_1 +
                (temp_src[e] + temp_src[w] - 2.0f * temp_src[idx]) * Rx_1 +
                (local_amb_temp - temp_src[idx]) * Rz_1
            );
        }
    }
}

int compute_tran_temp(float *MatrixPower, float *MatrixTemp[2], int col, int row,
                      int total_iterations, int num_iterations, int blockCols, int blockRows, int borderCols, int borderRows)
{
    (void)blockCols;
    (void)blockRows;
    (void)borderCols;
    (void)borderRows;

    float grid_height = chip_height / row;
    float grid_width = chip_width / col;

    float Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * grid_width * grid_height;
    float Rx = grid_width / (2.0f * K_SI * t_chip * grid_height);
    float Ry = grid_height / (2.0f * K_SI * t_chip * grid_width);
    float Rz = t_chip / (K_SI * grid_height * grid_width);

    float max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    float step = PRECISION / max_slope;
    float t;
    float time_elapsed;
    time_elapsed = 0.001f;
    (void)time_elapsed;

    int src = 1, dst = 0;
    int size = row * col;

    for (t = 0; t < total_iterations; t += num_iterations) {
        int temp = src;
        src = dst;
        dst = temp;

        int iter = MIN(num_iterations, total_iterations - (int)t);
        float *cur = MatrixTemp[src];
        float *next = MatrixTemp[dst];

        for (int i = 0; i < iter; i++) {
            calculate_temp_step(MatrixPower, cur, next, col, row, Cap, Rx, Ry, Rz, step);
            float *swap_ptr = cur;
            cur = next;
            next = swap_ptr;
        }

        if (cur != MatrixTemp[dst]) {
            memcpy(MatrixTemp[dst], cur, sizeof(float) * size);
        }
    }
    return dst;
}

