static void hotspotOpt1(float *p, float *tIn, float *tOut, float sdc,
        int nx, int ny, int nz,
        float ce, float cw,
        float cn, float cs,
        float ct, float cb,
        float cc)
{
    const float amb_temp_local = 80.0f;
    const int xy = nx * ny;

    #pragma omp parallel for collapse(2) schedule(static)
    for (int j = 0; j < ny; ++j) {
        for (int i = 0; i < nx; ++i) {
            int c = i + j * nx;
            int W = (i == 0) ? c : c - 1;
            int E = (i == nx - 1) ? c : c + 1;
            int N = (j == 0) ? c : c - nx;
            int S = (j == ny - 1) ? c : c + nx;

            if (nz <= 1) {
                float temp = tIn[c];
                tOut[c] = cc * temp + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
                    + cn * tIn[N] + cb * temp + ct * temp + sdc * p[c] + ct * amb_temp_local;
                continue;
            }

            float temp1, temp2, temp3;
            temp1 = temp2 = tIn[c];
            temp3 = tIn[c + xy];
            tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
                + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp_local;
            c += xy;
            W += xy;
            E += xy;
            N += xy;
            S += xy;

            for (int k = 1; k < nz - 1; ++k) {
                temp1 = temp2;
                temp2 = temp3;
                temp3 = tIn[c + xy];
                tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
                    + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp_local;
                c += xy;
                W += xy;
                E += xy;
                N += xy;
                S += xy;
            }
            temp1 = temp2;
            temp2 = temp3;
            tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
                + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp_local;
        }
    }
}

void hotspot_opt1(float *p, float *tIn, float *tOut,
        int nx, int ny, int nz,
        float Cap,
        float Rx, float Ry, float Rz,
        float dt, int numiter)
{
    float ce, cw, cn, cs, ct, cb, cc;
    float stepDivCap = dt / Cap;
    ce = cw = stepDivCap / Rx;
    cn = cs = stepDivCap / Ry;
    ct = cb = stepDivCap / Rz;

    cc = 1.0f - (2.0f * ce + 2.0f * cn + 3.0f * ct);

    size_t s = sizeof(float) * (size_t)nx * (size_t)ny * (size_t)nz;
    float *tIn_d, *tOut_d, *p_d;

    p_d = (float *)malloc(s);
    tIn_d = (float *)malloc(s);
    tOut_d = (float *)malloc(s);

    if (p_d == NULL || tIn_d == NULL || tOut_d == NULL) {
        fatal("memory allocation failed");
        free(p_d);
        free(tIn_d);
        free(tOut_d);
        return;
    }

    memcpy(tIn_d, tIn, s);
    memcpy(p_d, p, s);

    long long start = get_time();
    for (int i = 0; i < numiter; ++i) {
        hotspotOpt1(p_d, tIn_d, tOut_d, stepDivCap, nx, ny, nz, ce, cw, cn, cs, ct, cb, cc);
        {
            float *t = tIn_d;
            tIn_d = tOut_d;
            tOut_d = t;
        }
    }
    long long stop = get_time();
    {
        float time = (float)((stop - start) / (1000.0 * 1000.0));
        printf("Time: %.3f (s)\n", time);
    }

    memcpy(tOut, tOut_d, s);

    free(p_d);
    free(tIn_d);
    free(tOut_d);
}

int main(int argc, char **argv)
{
    if (argc != 7)
    {
        usage(argc, argv);
    }

    char *pfile, *tfile, *ofile;
    int iterations = atoi(argv[3]);

    pfile = argv[4];
    tfile = argv[5];
    ofile = argv[6];
    int numCols = atoi(argv[1]);
    int numRows = atoi(argv[1]);
    int layers = atoi(argv[2]);

    float dx = chip_height / numRows;
    float dy = chip_width / numCols;
    float dz = t_chip / layers;

    float Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * dx * dy;
    float Rx = dy / (2.0f * K_SI * t_chip * dx);
    float Ry = dx / (2.0f * K_SI * t_chip * dy);
    float Rz = dz / (K_SI * dx * dy);

    float max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    float dt = PRECISION / max_slope;

    float *powerIn, *tempOut, *tempIn, *tempCopy;
    int size = numCols * numRows * layers;

    powerIn = (float *)calloc((size_t)size, sizeof(float));
    tempCopy = (float *)malloc((size_t)size * sizeof(float));
    tempIn = (float *)calloc((size_t)size, sizeof(float));
    tempOut = (float *)calloc((size_t)size, sizeof(float));
