void lud_omp(float *m, int matrix_dim)
{
    int i;
    int blocks;

    omp_set_num_threads(omp_num_threads);

    for (i = 0; i < matrix_dim - BLOCK_SIZE; i += BLOCK_SIZE) {
        int bx, by;
        blocks = (matrix_dim - i) / BLOCK_SIZE - 1;

        lud_diagonal_omp(m, matrix_dim, i);

#pragma omp parallel for private(bx) schedule(static) num_threads(omp_num_threads)
        for (bx = 0; bx < blocks; bx++) {
            lud_perimeter_block_omp(m, matrix_dim, i, bx);
        }

#pragma omp parallel for collapse(2) private(by, bx) schedule(static) num_threads(omp_num_threads)
        for (by = 0; by < blocks; by++) {
            for (bx = 0; bx < blocks; bx++) {
                int ty, tx, k;
                int global_row_id = i + (by + 1) * BLOCK_SIZE;
                int global_col_id = i + (bx + 1) * BLOCK_SIZE;
                float peri_row[BLOCK_SIZE][BLOCK_SIZE];
                float peri_col[BLOCK_SIZE][BLOCK_SIZE];

                for (ty = 0; ty < BLOCK_SIZE; ty++) {
                    for (tx = 0; tx < BLOCK_SIZE; tx++) {
                        peri_row[ty][tx] = m[(i + ty) * matrix_dim + global_col_id + tx];
                        peri_col[ty][tx] = m[(global_row_id + ty) * matrix_dim + i + tx];
                    }
                }

                for (ty = 0; ty < BLOCK_SIZE; ty++) {
                    for (tx = 0; tx < BLOCK_SIZE; tx++) {
                        float sum = 0.0f;
                        for (k = 0; k < BLOCK_SIZE; k++) {
                            sum += peri_col[ty][k] * peri_row[k][tx];
                        }
                        m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;
                    }
                }
            }
        }
    }

    lud_diagonal_omp(m, matrix_dim, i);
}

