										 /(1+pow((d_initvalu_38/Kmf),hillSRCaP)+pow((d_initvalu_31/Kmr),hillSRCaP));
	J_SRleak = 5.348e-6f*(d_initvalu_31-d_initvalu_36);

	d_finavalu[offset_17] = kon_na*d_initvalu_32*(Bmax_Naj-d_initvalu_17)-koff_na*d_initvalu_17;
	d_finavalu[offset_18] = kon_na*d_initvalu_33*(Bmax_Nasl-d_initvalu_18)-koff_na*d_initvalu_18;

	d_finavalu[offset_19] = kon_tncl*d_initvalu_38*(Bmax_TnClow-d_initvalu_19)-koff_tncl*d_initvalu_19;
	d_finavalu[offset_20] = kon_tnchca*d_initvalu_38*(Bmax_TnChigh-d_initvalu_20-d_initvalu_21)-koff_tnchca*d_initvalu_20;
	d_finavalu[offset_21] = kon_tnchmg*Mgi*(Bmax_TnChigh-d_initvalu_20-d_initvalu_21)-koff_tnchmg*d_initvalu_21;
	d_finavalu[offset_22] = 0;
	d_finavalu[offset_23] = kon_myoca*d_initvalu_38*(Bmax_myosin-d_initvalu_23-d_initvalu_24)-koff_myoca*d_initvalu_23;
	d_finavalu[offset_24] = kon_myomg*Mgi*(Bmax_myosin-d_initvalu_23-d_initvalu_24)-koff_myomg*d_initvalu_24;
	d_finavalu[offset_25] = kon_sr*d_initvalu_38*(Bmax_SR-d_initvalu_25)-koff_sr*d_initvalu_25;
	J_CaB_cytosol = d_finavalu[offset_19] + d_finavalu[offset_20] + d_finavalu[offset_21] + d_finavalu[offset_22] + d_finavalu[offset_23] + d_finavalu[offset_24] + d_finavalu[offset_25];

	d_finavalu[offset_26] = kon_sll*d_initvalu_36*(Bmax_SLlowj-d_initvalu_26)-koff_sll*d_initvalu_26;
	d_finavalu[offset_27] = kon_sll*d_initvalu_37*(Bmax_SLlowsl-d_initvalu_27)-koff_sll*d_initvalu_27;
	d_finavalu[offset_28] = kon_slh*d_initvalu_36*(Bmax_SLhighj-d_initvalu_28)-koff_slh*d_initvalu_28;
	d_finavalu[offset_29] = kon_slh*d_initvalu_37*(Bmax_SLhighsl-d_initvalu_29)-koff_slh*d_initvalu_29;
	J_CaB_junction = d_finavalu[offset_26]+d_finavalu[offset_28];
	J_CaB_sl = d_finavalu[offset_27]+d_finavalu[offset_29];

	d_finavalu[offset_30] = kon_csqn*d_initvalu_31*(Bmax_Csqn-d_initvalu_30)-koff_csqn*d_initvalu_30;
	oneovervsr = 1/Vsr;
	d_finavalu[offset_31] = J_serca*Vmyo*oneovervsr-(J_SRleak*Vmyo*oneovervsr+J_SRCarel)-d_finavalu[offset_30];

	I_Na_tot_junc = I_Na_junc+I_nabk_junc+3*I_ncx_junc+3*I_nak_junc+I_CaNa_junc;
	I_Na_tot_sl = I_Na_sl+I_nabk_sl+3*I_ncx_sl+3*I_nak_sl+I_CaNa_sl;
	d_finavalu[offset_32] = -I_Na_tot_junc*Cmem/(Vjunc*Frdy)+J_na_juncsl/Vjunc*(d_initvalu_33-d_initvalu_32)-d_finavalu[offset_17];
	oneovervsl = 1/Vsl;
	d_finavalu[offset_33] = -I_Na_tot_sl*Cmem*oneovervsl/Frdy+J_na_juncsl*oneovervsl*(d_initvalu_32-d_initvalu_33)+J_na_slmyo*oneovervsl*(d_initvalu_34-d_initvalu_33)-d_finavalu[offset_18];
	d_finavalu[offset_34] = J_na_slmyo/Vmyo*(d_initvalu_33-d_initvalu_34);

	I_K_tot = I_to+I_kr+I_ks+I_ki-2*I_nak+I_CaK+I_kp;
	d_finavalu[offset_35] = 0;

	I_Ca_tot_junc = I_Ca_junc+I_cabk_junc+I_pca_junc-2*I_ncx_junc;
	I_Ca_tot_sl = I_Ca_sl+I_cabk_sl+I_pca_sl-2*I_ncx_sl;
	d_finavalu[offset_36] = -I_Ca_tot_junc*Cmem/(Vjunc*2*Frdy)+J_ca_juncsl/Vjunc*(d_initvalu_37-d_initvalu_36)
	         - J_CaB_junction+(J_SRCarel)*Vsr/Vjunc+J_SRleak*Vmyo/Vjunc;
	d_finavalu[offset_37] = -I_Ca_tot_sl*Cmem/(Vsl*2*Frdy)+J_ca_juncsl/Vsl*(d_initvalu_36-d_initvalu_37)
	         + J_ca_slmyo/Vsl*(d_initvalu_38-d_initvalu_37)-J_CaB_sl;
	d_finavalu[offset_38] = -J_serca-J_CaB_cytosol +J_ca_slmyo/Vmyo*(d_initvalu_37-d_initvalu_38);

	state = 1;
	switch(state){
		case 0:
			I_app = 0;
			break;
		case 1:
			if(fmod(timeinst,cycleLength) <= 5){
				I_app = 9.5f;
			}
			else{
				I_app = 0.0f;
			}
			break;
		case 2:
			V_hold = -55;
			V_test = 0;
			if(timeinst>0.5f & timeinst<200.5f){
				V_clamp = V_test;
			}
			else{
				V_clamp = V_hold;
			}
			R_clamp = 0.04f;
			I_app = (V_clamp-d_initvalu_39)/R_clamp;
			break;
		default:
			I_app = 0.0f;
			break;
	}

	I_Na_tot = I_Na_tot_junc + I_Na_tot_sl;
	I_Cl_tot = I_ClCa+I_Clbk;
	I_Ca_tot = I_Ca_tot_junc+I_Ca_tot_sl;
	I_tot = I_Na_tot+I_Cl_tot+I_Ca_tot+I_K_tot;
	d_finavalu[offset_39] = -(I_tot-I_app);

	d_finavalu[offset_41] = 0;
	d_finavalu[offset_42] = 0;
}

static void kernel_fin_cpu(	fp *initvalu,
														int initvalu_offset_ecc,
														int initvalu_offset_Dyad,
														int initvalu_offset_SL,
														int initvalu_offset_Cyt,
														fp *parameter,
														fp *finavalu,
														fp JCaDyad,
														fp JCaSL,
														fp JCaCyt){

	fp BtotDyad;
	fp CaMKIItotDyad;

	fp Vmyo;
	fp Vdyad;
	fp VSL;

	fp kSLmyo;
	fp k0Boff;
	fp k0Bon;
	fp k2Boff;
	fp k2Bon;

	fp k4Bon;
	fp CaMtotDyad;
	fp Bdyad;
	fp J_cam_dyadSL;
	fp J_ca2cam_dyadSL;
	fp J_ca4cam_dyadSL;
	fp J_cam_SLmyo;
	fp J_ca2cam_SLmyo;
	fp J_ca4cam_SLmyo;

	BtotDyad      = parameter[2];
	CaMKIItotDyad = parameter[3];

	Vmyo = 2.1454e-11f;
	Vdyad = 1.7790e-14f;
	VSL = 6.6013e-13f;

	kSLmyo = 8.587e-15f;
	k0Boff = 0.0014f;
	k0Bon = k0Boff/0.2f;
	k2Boff = k0Boff/100;
	k2Bon = k0Bon;
	k4Bon = k0Bon;

	finavalu[initvalu_offset_ecc+35] = finavalu[initvalu_offset_ecc+35] + 1e-3f*JCaDyad;
	finavalu[initvalu_offset_ecc+36] = finavalu[initvalu_offset_ecc+36] + 1e-3f*JCaSL;
	finavalu[initvalu_offset_ecc+37] = finavalu[initvalu_offset_ecc+37] + 1e-3f*JCaCyt;

	CaMtotDyad = initvalu[initvalu_offset_Dyad+0]
			   + initvalu[initvalu_offset_Dyad+1]
			   + initvalu[initvalu_offset_Dyad+2]
			   + initvalu[initvalu_offset_Dyad+3]
			   + initvalu[initvalu_offset_Dyad+4]
			   + initvalu[initvalu_offset_Dyad+5]
			   + CaMKIItotDyad * (  initvalu[initvalu_offset_Dyad+6]
								  + initvalu[initvalu_offset_Dyad+7]
								  + initvalu[initvalu_offset_Dyad+8]
								  + initvalu[initvalu_offset_Dyad+9])
			   + initvalu[initvalu_offset_Dyad+12]
			   + initvalu[initvalu_offset_Dyad+13]
			   + initvalu[initvalu_offset_Dyad+14];
	Bdyad = BtotDyad - CaMtotDyad;
	J_cam_dyadSL = 1e-3f * (  k0Boff*initvalu[initvalu_offset_Dyad+0] - k0Bon*Bdyad*initvalu[initvalu_offset_SL+0]);
	J_ca2cam_dyadSL = 1e-3f * (  k2Boff*initvalu[initvalu_offset_Dyad+1] - k2Bon*Bdyad*initvalu[initvalu_offset_SL+1]);
	J_ca4cam_dyadSL = 1e-3f * (  k2Boff*initvalu[initvalu_offset_Dyad+2] - k4Bon*Bdyad*initvalu[initvalu_offset_SL+2]);

	J_cam_SLmyo = kSLmyo * (  initvalu[initvalu_offset_SL+0] - initvalu[initvalu_offset_Cyt+0]);
	J_ca2cam_SLmyo = kSLmyo * (  initvalu[initvalu_offset_SL+1] - initvalu[initvalu_offset_Cyt+1]);
	J_ca4cam_SLmyo = kSLmyo * (  initvalu[initvalu_offset_SL+2] - initvalu[initvalu_offset_Cyt+2]);

	finavalu[initvalu_offset_Dyad+0] = finavalu[initvalu_offset_Dyad+0] - J_cam_dyadSL;
	finavalu[initvalu_offset_Dyad+1] = finavalu[initvalu_offset_Dyad+1] - J_ca2cam_dyadSL;
	finavalu[initvalu_offset_Dyad+2] = finavalu[initvalu_offset_Dyad+2] - J_ca4cam_dyadSL;

	finavalu[initvalu_offset_SL+0] = finavalu[initvalu_offset_SL+0] + J_cam_dyadSL*Vdyad/VSL - J_cam_SLmyo/VSL;
	finavalu[initvalu_offset_SL+1] = finavalu[initvalu_offset_SL+1] + J_ca2cam_dyadSL*Vdyad/VSL - J_ca2cam_SLmyo/VSL;
	finavalu[initvalu_offset_SL+2] = finavalu[initvalu_offset_SL+2] + J_ca4cam_dyadSL*Vdyad/VSL - J_ca4cam_SLmyo/VSL;

	finavalu[initvalu_offset_Cyt+0] = finavalu[initvalu_offset_Cyt+0] + J_cam_SLmyo/Vmyo;
	finavalu[initvalu_offset_Cyt+1] = finavalu[initvalu_offset_Cyt+1] + J_ca2cam_SLmyo/Vmyo;
	finavalu[initvalu_offset_Cyt+2] = finavalu[initvalu_offset_Cyt+2] + J_ca4cam_SLmyo/Vmyo;
}

static void kernel_2_cpu(	int timeinst,
													fp* initvalu,
													fp* params,
													fp* finavalu,
													fp* com){

	int valu_offset_ecc;
	int valu_offset_Dyad;
	int valu_offset_SL;
	int valu_offset_Cyt;

	int params_offset_Dyad;
	int params_offset_SL;
	int params_offset_Cyt;

	int com_offset_Dyad;
	int com_offset_SL;
	int com_offset_Cyt;

	fp CaDyad;
	fp CaSL;
	fp CaCyt;

	int i;

	valu_offset_ecc = 0;
	valu_offset_Dyad = 46;
	valu_offset_SL = 61;
	valu_offset_Cyt = 76;

	params_offset_Dyad = 0;
	params_offset_SL = 5;
	params_offset_Cyt = 10;

	com_offset_Dyad = 0;
	com_offset_SL = 1;
	com_offset_Cyt = 2;

	kernel_ecc_cpu(	timeinst,
									initvalu,
									finavalu,
									valu_offset_ecc,
									params);

	CaDyad = initvalu[35]*1e3f;
	kernel_cam_cpu(	timeinst,
									initvalu,
									finavalu,
									valu_offset_Dyad,
									params,
									params_offset_Dyad,
									com,
									com_offset_Dyad,
									CaDyad);

	CaSL = initvalu[36]*1e3f;
	kernel_cam_cpu(	timeinst,
									initvalu,
									finavalu,
									valu_offset_SL,
									params,
									params_offset_SL,
									com,
									com_offset_SL,
									CaSL);

	CaCyt = initvalu[37]*1e3f;
	kernel_cam_cpu(	timeinst,
									initvalu,
									finavalu,
									valu_offset_Cyt,
									params,
									params_offset_Cyt,
									com,
									com_offset_Cyt,
									CaCyt);

	kernel_fin_cpu(	initvalu,
									valu_offset_ecc,
									valu_offset_Dyad,
									valu_offset_SL,
									valu_offset_Cyt,
									params,
									finavalu,
									com[0],
									com[1],
									com[2]);

	for(i=0; i<EQUATIONS; i++){
		if (isnan(finavalu[i]) == 1){
			finavalu[i] = 0.0001f;
		}
		else if (isinf(finavalu[i]) == 1){
			finavalu[i] = 0.0001f;
		}
	}
}

