			timeinst_temp = timeinst;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h * ( b12_1*finavalu_temp[0*EQUATIONS+i] + b12_6*finavalu_temp[5*EQUATIONS+i] + b12_7*finavalu_temp[6*EQUATIONS+i] + b12_8*finavalu_temp[7*EQUATIONS+i] + b12_9*finavalu_temp[8*EQUATIONS+i] + b12_10 * finavalu_temp[9*EQUATIONS+i]) ;
			}
		}
		else{
			timeinst_temp = timeinst+h;
			for(i=0; i<EQUATIONS; i++){
				initvalu_temp[i] = initvalu[i] + h * ( b13_1*finavalu_temp[0*EQUATIONS+i] + b13_4*finavalu_temp[3*EQUATIONS+i] + b13_5*finavalu_temp[4*EQUATIONS+i] + b13_6*finavalu_temp[5*EQUATIONS+i] + b13_7*finavalu_temp[6*EQUATIONS+i] + b13_8*finavalu_temp[7*EQUATIONS+i] + b13_9*finavalu_temp[8*EQUATIONS+i] + b13_10*finavalu_temp[9*EQUATIONS+i] + finavalu_temp[11*EQUATIONS+i]) ;
			}
		}

		kernel_2_cpu(	(int)timeinst_temp,
									initvalu_temp,
									parameter,
									&finavalu_temp[j*EQUATIONS],
									com);
	}

	for(i=0; i<EQUATIONS; i++){
		finavalu[i]= initvalu[i] +  h * (c_1_11 * (finavalu_temp[0*EQUATIONS+i] + finavalu_temp[10*EQUATIONS+i])  + c6 * finavalu_temp[5*EQUATIONS+i] + c_7_8 * (finavalu_temp[6*EQUATIONS+i] + finavalu_temp[7*EQUATIONS+i]) + c_9_10 * (finavalu_temp[8*EQUATIONS+i] + finavalu_temp[9*EQUATIONS+i]) );
	}

	for(i=0; i<EQUATIONS; i++){
		error[i] = fabs(err_factor * (finavalu_temp[0*EQUATIONS+i] + finavalu_temp[10*EQUATIONS+i] - finavalu_temp[11*EQUATIONS+i] - finavalu_temp[12*EQUATIONS+i]));
	}
}

static void embedded_fehlberg_7_8_cpu(	fp timeinst,
																				fp h,
																				fp* initvalu,
																				fp* finavalu,
																				fp* error,
																				fp* parameter,
																				fp* com) {
	fp initvalu_temp[EQUATIONS];
	fp finavalu_temp[13*EQUATIONS];
	embedded_fehlberg_7_8_2_cpu(h, timeinst, initvalu, finavalu, parameter, error, initvalu_temp, finavalu_temp, com);
}

static int solver_cpu(	fp** y,
												fp* x,
												int xmax,
												fp* params,
												fp* com) {

	fp err_exponent;
	int error;
	int outside;
	fp h;
	fp h_init;
	fp tolerance;
	int xmin;

	fp scale_min;
	fp scale_fina;
	fp* err= (fp *) malloc(EQUATIONS* sizeof(fp));
	fp* scale= (fp *) malloc(EQUATIONS* sizeof(fp));
	fp* yy= (fp *) malloc(EQUATIONS* sizeof(fp));

	int i, j, k;

	err_exponent = 1.0f / 7.0f;
	h_init = 1;
	h = h_init;
	xmin = 0;
	tolerance = 10 / (fp)(xmax-xmin);

	x[0] = 0;

	if (xmax < xmin || h <= 0.0f){
		free(err);
		free(scale);
		free(yy);
		return -2;
	}

	if (xmax == xmin){
		free(err);
		free(scale);
		free(yy);
		return 0;
	}

	if (h > (xmax - xmin) ) {
		h = (fp)xmax - (fp)xmin;
	}

	for(k=1; k<=xmax; k++) {

		x[k] = k-1;
		h = h_init;

		scale_fina = 1.0f;

		for (j = 0; j < ATTEMPTS; j++) {

			error = 0;
			outside = 0;
			scale_min = MAX_SCALE_FACTOR;

			embedded_fehlberg_7_8_cpu(	x[k],
																	h,
																	y[k-1],
																	y[k],
																	err,
																	params,
																	com);

			for(i=0; i<EQUATIONS; i++){
				if(err[i] > 0){
					error = 1;
				}
			}
			if (error != 1) {
				scale_fina = MAX_SCALE_FACTOR;
				break;
			}

			for(i=0; i<EQUATIONS; i++){
				if(y[k-1][i] == 0.0f){
					yy[i] = tolerance;
				}
				else{
					yy[i] = fabs(y[k-1][i]);
				}
				scale[i] = 0.8f * pow( tolerance * yy[i] / err[i] , err_exponent );
				if(scale[i]<scale_min){
					scale_min = scale[i];
				}
			}
			scale_fina = min( max(scale_min,MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);

			for(i=0; i<EQUATIONS; i++){
				if ( err[i] > ( tolerance * yy[i] ) ){
					outside = 1;
				}
			}
			if (outside == 0){
				break;
			}

			h = h * scale_fina;

			if (h >= 0.9f) {
				h = 0.9f;
			}

			if ( x[k] + h > (fp)xmax ){
				h = (fp)xmax - x[k];
			}
			else if ( x[k] + h + 0.5f * h > (fp)xmax ){
				h = 0.5f * h;
			}
		}

		x[k] = x[k] + h;

		if ( j >= ATTEMPTS ) {
			free(err);
			free(scale);
			free(yy);
			return -1;
		}
	}

	free(err);
	free(scale);
	free(yy);

	return 0;
}

static int work(	int xmax,
