static inline int maximum(int a, int b, int c) {
    int k;
    if (a <= b)
        k = b;
    else
        k = a;

    if (k <= c)
        return c;
    else
        return k;
}

static inline void compute_tile(int* referrence, int* matrix_cuda, int cols, int penalty, int b_index_x, int b_index_y) {
    int base = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;
    int temp[BLOCK_SIZE + 1][BLOCK_SIZE + 1];
    int ref[BLOCK_SIZE][BLOCK_SIZE];

    temp[0][0] = matrix_cuda[base];

    for (int x = 1; x <= BLOCK_SIZE; x++) {
        temp[0][x] = matrix_cuda[base + x];
    }

    for (int y = 1; y <= BLOCK_SIZE; y++) {
        temp[y][0] = matrix_cuda[base + cols * y];
    }

    for (int y = 0; y < BLOCK_SIZE; y++) {
        for (int x = 0; x < BLOCK_SIZE; x++) {
            ref[y][x] = referrence[base + cols * (y + 1) + (x + 1)];
        }
    }

    for (int y = 1; y <= BLOCK_SIZE; y++) {
        for (int x = 1; x <= BLOCK_SIZE; x++) {
            temp[y][x] = maximum(temp[y - 1][x - 1] + ref[y - 1][x - 1],
                                 temp[y][x - 1] - penalty,
                                 temp[y - 1][x] - penalty);
        }
    }

    for (int y = 1; y <= BLOCK_SIZE; y++) {
        for (int x = 1; x <= BLOCK_SIZE; x++) {
            matrix_cuda[base + cols * y + x] = temp[y][x];
        }
    }
}

static inline void needle_cuda_shared_1(int* referrence,
                                        int* matrix_cuda,
                                        int cols,
                                        int penalty,
                                        int i,
                                        int block_width) {
    (void)block_width;
    #pragma omp parallel for schedule(static)
    for (int bx = 0; bx < i; bx++) {
        int b_index_x = bx;
        int b_index_y = i - 1 - bx;
        compute_tile(referrence, matrix_cuda, cols, penalty, b_index_x, b_index_y);
    }
}

static inline void needle_cuda_shared_2(int* referrence,
                                        int* matrix_cuda,
                                        int cols,
                                        int penalty,
                                        int i,
                                        int block_width) {
    #pragma omp parallel for schedule(static)
    for (int bx = 0; bx < i; bx++) {
        int b_index_x = bx + block_width - i;
        int b_index_y = block_width - bx - 1;
        compute_tile(referrence, matrix_cuda, cols, penalty, b_index_x, b_index_y);
    }
}

