static inline int maximum(int a, int b, int c) {
  int k;
  if (a <= b)
    k = b;
  else
    k = a;

  if (k <= c)
    return c;
  else
    return k;
}

static void process_tile(int *referrence, int *matrix_cuda, int cols, int penalty,
                         int b_index_x, int b_index_y) {
  int base = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;
  int temp[BLOCK_SIZE + 1][BLOCK_SIZE + 1];
  int ref[BLOCK_SIZE][BLOCK_SIZE];

  temp[0][0] = matrix_cuda[base];

  for (int tx = 0; tx < BLOCK_SIZE; tx++) {
    temp[tx + 1][0] = matrix_cuda[base + cols * (tx + 1)];
    temp[0][tx + 1] = matrix_cuda[base + tx + 1];
  }

  for (int ty = 0; ty < BLOCK_SIZE; ty++) {
    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
      ref[ty][tx] = referrence[base + (cols + 1) + tx + cols * ty];
    }
  }

  for (int r = 1; r <= BLOCK_SIZE; r++) {
    for (int c = 1; c <= BLOCK_SIZE; c++) {
      temp[r][c] = maximum(temp[r - 1][c - 1] + ref[r - 1][c - 1],
                           temp[r][c - 1] - penalty,
                           temp[r - 1][c] - penalty);
    }
  }

  for (int ty = 0; ty < BLOCK_SIZE; ty++) {
    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
      matrix_cuda[base + (cols + 1) + tx + ty * cols] = temp[ty + 1][tx + 1];
    }
  }
}

static void needle_cuda_shared_1(int *referrence, int *matrix_cuda, int cols,
                                 int penalty, int i, int block_width) {
#pragma omp parallel for schedule(static)
  for (int bx = 0; bx < i; bx++) {
    int b_index_x = bx;
    int b_index_y = i - 1 - bx;
    process_tile(referrence, matrix_cuda, cols, penalty, b_index_x, b_index_y);
  }
}

static void needle_cuda_shared_2(int *referrence, int *matrix_cuda, int cols,
                                 int penalty, int i, int block_width) {
#pragma omp parallel for schedule(static)
  for (int bx = 0; bx < i; bx++) {
    int b_index_x = bx + block_width - i;
    int b_index_y = block_width - bx - 1;
    process_tile(referrence, matrix_cuda, cols, penalty, b_index_x, b_index_y);
  }
}

