    seed[index] = num % M;
    return fabs(seed[index] / ((double) M));
}

double randn(int *seed, int index) {
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2 * PI * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

double d_randn(int *seed, int index) {
    double pi = 3.14159265358979323846;
    double u = d_randu(seed, index);
    double v = d_randu(seed, index);
    double cosine = cos(2 * pi * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

double dev_round_double(double value) {
    int newValue = (int) (value);
    if (value - newValue < .5f)
        return newValue;
    else
        return newValue++;
}

double roundDouble(double value) {
    int newValue = (int) (value);
    if (value - newValue < .5)
        return newValue;
    else
        return newValue++;
}

void setIf(int testValue, int newValue, unsigned char *array3D, int *dimX, int *dimY, int *dimZ) {
    int x, y, z;
    for (x = 0; x < *dimX; x++) {
        for (y = 0; y < *dimY; y++) {
            for (z = 0; z < *dimZ; z++) {
                if (array3D[x * *dimY * *dimZ + y * *dimZ + z] == testValue)
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] = newValue;
            }
        }
    }
}

void addNoise(unsigned char *array3D, int *dimX, int *dimY, int *dimZ, int *seed) {
    int x, y, z;
    for (x = 0; x < *dimX; x++) {
        for (y = 0; y < *dimY; y++) {
            for (z = 0; z < *dimZ; z++) {
                array3D[x * *dimY * *dimZ + y * *dimZ + z] =
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] + (unsigned char) (5 * randn(seed, 0));
            }
        }
    }
}

void strelDisk(int *disk, int radius) {
    int diameter = radius * 2 - 1;
    int x, y;
    for (x = 0; x < diameter; x++) {
        for (y = 0; y < diameter; y++) {
            double distance = sqrt(pow((double) (x - radius + 1), 2) + pow((double) (y - radius + 1), 2));
            if (distance < radius)
                disk[x * diameter + y] = 1;
            else
                disk[x * diameter + y] = 0;
        }
    }
}

void dilate_matrix(unsigned char *matrix, int posX, int posY, int posZ, int dimX, int dimY, int dimZ, int error) {
    int startX = posX - error;
    while (startX < 0)
        startX++;
    int startY = posY - error;
    while (startY < 0)
        startY++;
    int endX = posX + error;
    while (endX > dimX)
        endX--;
    int endY = posY + error;
    while (endY > dimY)
        endY--;
    int x, y;
    for (x = startX; x < endX; x++) {
        for (y = startY; y < endY; y++) {
            double distance = sqrt(pow((double) (x - posX), 2) + pow((double) (y - posY), 2));
            if (distance < error)
                matrix[x * dimY * dimZ + y * dimZ + posZ] = 1;
        }
    }
}

void imdilate_disk(unsigned char *matrix, int dimX, int dimY, int dimZ, int error, unsigned char *newMatrix) {
    int x, y, z;
    for (z = 0; z < dimZ; z++) {
        for (x = 0; x < dimX; x++) {
            for (y = 0; y < dimY; y++) {
                if (matrix[x * dimY * dimZ + y * dimZ + z] == 1) {
                    dilate_matrix(newMatrix, x, y, z, dimX, dimY, dimZ, error);
                }
            }
        }
    }
}

void getneighbors(int *se, int numOnes, int *neighbors, int radius) {
    int x, y;
    int neighY = 0;
    int center = radius - 1;
    int diameter = radius * 2 - 1;
    for (x = 0; x < diameter; x++) {
        for (y = 0; y < diameter; y++) {
            if (se[x * diameter + y]) {
                neighbors[neighY * 2] = (int) (y - center);
                neighbors[neighY * 2 + 1] = (int) (x - center);
                neighY++;
            }
        }
    }
}

void videoSequence(unsigned char *I, int IszX, int IszY, int Nfr, int *seed) {
    int k;
    int max_size = IszX * IszY * Nfr;

    memset(I, 0, sizeof(unsigned char) * IszX * IszY * Nfr);

    int x0 = (int) roundDouble(IszY / 2.0);
    int y0 = (int) roundDouble(IszX / 2.0);
    I[x0 * IszY * Nfr + y0 * Nfr + 0] = 1;

    int xk, yk, pos;
    for (k = 1; k < Nfr; k++) {
        xk = abs(x0 + (k - 1));
        yk = abs(y0 - 2 * (k - 1));
        pos = yk * IszY * Nfr + xk * Nfr + k;
        if (pos >= max_size)
            pos = 0;
        I[pos] = 1;
    }

    unsigned char *newMatrix = (unsigned char *) calloc((size_t) IszX * IszY * Nfr, sizeof(unsigned char));
    imdilate_disk(I, IszX, IszY, Nfr, 5, newMatrix);
    int x, y;
    for (x = 0; x < IszX; x++) {
        for (y = 0; y < IszY; y++) {
            for (k = 0; k < Nfr; k++) {
                I[x * IszY * Nfr + y * Nfr + k] = newMatrix[x * IszY * Nfr + y * Nfr + k];
            }
        }
    }
    free(newMatrix);

    setIf(0, 100, I, &IszX, &IszY, &Nfr);
    setIf(1, 228, I, &IszX, &IszY, &Nfr);

    addNoise(I, &IszX, &IszY, &Nfr, seed);
}

int findIndex(double *CDF, int lengthCDF, double value) {
    int index = -1;
    int x;
    for (x = 0; x < lengthCDF; x++) {
        if (CDF[x] >= value) {
            index = x;
            break;
        }
    }
    if (index == -1) {
        return lengthCDF - 1;
    }
    return index;
}

void likelihood_kernel_omp(double *arrayX, double *arrayY, double *xj, double *yj, int *ind, int *objxy,
                           double *likelihood, unsigned char *I, double *weights, int Nparticles,
                           int countOnes, int max_size, int k, int IszY, int Nfr, int *seed,
                           double *partial_sums) {
    int num_blocks = (int) ceil((double) Nparticles / (double) threads_per_block);
    int b, i, y;

    #pragma omp parallel for private(y) schedule(static)
    for (i = 0; i < Nparticles; i++) {
        int indX, indY;
        arrayX[i] = xj[i];
        arrayY[i] = yj[i];

        weights[i] = 1 / ((double) (Nparticles));

        arrayX[i] = arrayX[i] + 1.0 + 5.0 * d_randn(seed, i);
        arrayY[i] = arrayY[i] - 2.0 + 2.0 * d_randn(seed, i);

        for (y = 0; y < countOnes; y++) {
            indX = (int) dev_round_double(arrayX[i]) + objxy[y * 2 + 1];
            indY = (int) dev_round_double(arrayY[i]) + objxy[y * 2];

            ind[i * countOnes + y] = abs(indX * IszY * Nfr + indY * Nfr + k);
            if (ind[i * countOnes + y] >= max_size)
                ind[i * countOnes + y] = 0;
        }
        likelihood[i] = calcLikelihoodSum(I, ind, countOnes, i);
        likelihood[i] = likelihood[i] / countOnes;
        weights[i] = weights[i] * exp(likelihood[i]);
    }

    for (b = 0; b < num_blocks; b++) {
        double sum = 0.0;
        int start = b * threads_per_block;
        int end = start + threads_per_block;
        if (end > Nparticles)
            end = Nparticles;
        for (i = start; i < end; i++) {
            sum += weights[i];
        }
        partial_sums[b] = sum;
    }
}

void sum_kernel_omp(double *partial_sums, int Nparticles) {
    int x;
    double sum = 0.0;
    int num_blocks = (int) ceil((double) Nparticles / (double) threads_per_block);
    for (x = 0; x < num_blocks; x++) {
        sum += partial_sums[x];
    }
    partial_sums[0] = sum;
}

void normalize_weights_kernel_omp(double *weights, int Nparticles, double *partial_sums, double *CDF, double *u, int *seed) {
    int i;
    double sumWeights = partial_sums[0];

    #pragma omp parallel for schedule(static)
    for (i = 0; i < Nparticles; i++) {
        weights[i] = weights[i] / sumWeights;
    }

    cdfCalc(CDF, weights, Nparticles);
    u[0] = (1 / ((double) (Nparticles))) * d_randu(seed, 0);

    {
        double u1 = u[0];
        #pragma omp parallel for schedule(static)
        for (i = 0; i < Nparticles; i++) {
            u[i] = u1 + i / ((double) (Nparticles));
        }
    }
}

void find_index_kernel_omp(double *arrayX, double *arrayY, double *CDF, double *u, double *xj, double *yj,
                           double *weights, int Nparticles) {
    int i;
    (void) weights;

    #pragma omp parallel for schedule(static)
    for (i = 0; i < Nparticles; i++) {
        int index = -1;
        int x;

        for (x = 0; x < Nparticles; x++) {
            if (CDF[x] >= u[i]) {
                index = x;
                break;
            }
        }
        if (index == -1) {
            index = Nparticles - 1;
        }

        xj[i] = arrayX[index];
        yj[i] = arrayY[index];
    }
}

void particleFilter(unsigned char *I, int IszX, int IszY, int Nfr, int *seed, int Nparticles) {
    int max_size = IszX * IszY * Nfr;

    double xe = roundDouble(IszY / 2.0);
    double ye = roundDouble(IszX / 2.0);

    int radius = 5;
    int diameter = radius * 2 - 1;
    int *disk = (int *) malloc((size_t) diameter * diameter * sizeof(int));
    strelDisk(disk, radius);
    int countOnes = 0;
    int x, y;
    for (x = 0; x < diameter; x++) {
        for (y = 0; y < diameter; y++) {
            if (disk[x * diameter + y] == 1)
                countOnes++;
        }
    }
    int *objxy = (int *) malloc((size_t) countOnes * 2 * sizeof(int));
    getneighbors(disk, countOnes, objxy, radius);

    double *weights = (double *) malloc(sizeof(double) * Nparticles);
    for (x = 0; x < Nparticles; x++) {
        weights[x] = 1 / ((double) (Nparticles));
    }

    double *likelihood = (double *) malloc(sizeof(double) * Nparticles);
    double *arrayX = (double *) malloc(sizeof(double) * Nparticles);
    double *arrayY = (double *) malloc(sizeof(double) * Nparticles);
    double *xj = (double *) malloc(sizeof(double) * Nparticles);
    double *yj = (double *) malloc(sizeof(double) * Nparticles);
    double *CDF = (double *) malloc(sizeof(double) * Nparticles);

    double *arrayX_GPU = (double *) malloc(sizeof(double) * Nparticles);
    double *arrayY_GPU = (double *) malloc(sizeof(double) * Nparticles);
    double *xj_GPU = (double *) malloc(sizeof(double) * Nparticles);
    double *yj_GPU = (double *) malloc(sizeof(double) * Nparticles);
    double *CDF_GPU = (double *) malloc(sizeof(double) * Nparticles);
    double *likelihood_GPU = (double *) calloc((size_t) Nparticles, sizeof(double));
    unsigned char *I_GPU = (unsigned char *) malloc(sizeof(unsigned char) * IszX * IszY * Nfr);
    double *weights_GPU = (double *) malloc(sizeof(double) * Nparticles);
    int *objxy_GPU = (int *) malloc(sizeof(int) * 2 * countOnes);

    int *ind = (int *) malloc(sizeof(int) * countOnes * Nparticles);
    int *ind_GPU = (int *) malloc(sizeof(int) * countOnes * Nparticles);
    double *u = (double *) malloc(sizeof(double) * Nparticles);
    double *u_GPU = (double *) malloc(sizeof(double) * Nparticles);
    int *seed_GPU = (int *) malloc(sizeof(int) * Nparticles);
    double *partial_sums = (double *) malloc(sizeof(double) * Nparticles);

    for (x = 0; x < Nparticles; x++) {
        xj[x] = xe;
        yj[x] = ye;
    }

    int k;

    long long send_start = get_time();
    memcpy(I_GPU, I, sizeof(unsigned char) * IszX * IszY * Nfr);
    memcpy(objxy_GPU, objxy, sizeof(int) * 2 * countOnes);
    memcpy(weights_GPU, weights, sizeof(double) * Nparticles);
    memcpy(xj_GPU, xj, sizeof(double) * Nparticles);
    memcpy(yj_GPU, yj, sizeof(double) * Nparticles);
    memcpy(seed_GPU, seed, sizeof(int) * Nparticles);
    long long send_end = get_time();
    printf("TIME TO SEND TO GPU: %f\n", elapsed_time(send_start, send_end));
    int num_blocks = (int) ceil((double) Nparticles / (double) threads_per_block);
    (void) num_blocks;

    for (k = 1; k < Nfr; k++) {
        likelihood_kernel_omp(arrayX_GPU, arrayY_GPU, xj_GPU, yj_GPU, ind_GPU, objxy_GPU,
                              likelihood_GPU, I_GPU, weights_GPU, Nparticles, countOnes,
                              max_size, k, IszY, Nfr, seed_GPU, partial_sums);

        sum_kernel_omp(partial_sums, Nparticles);

        normalize_weights_kernel_omp(weights_GPU, Nparticles, partial_sums, CDF_GPU, u_GPU, seed_GPU);

        find_index_kernel_omp(arrayX_GPU, arrayY_GPU, CDF_GPU, u_GPU, xj_GPU, yj_GPU, weights_GPU, Nparticles);
    }

    long long back_time = get_time();

    free(xj_GPU);
    free(yj_GPU);
    free(CDF_GPU);
    free(u_GPU);
    free(likelihood_GPU);
    free(I_GPU);
    free(objxy_GPU);
    free(ind_GPU);
    free(seed_GPU);
    free(partial_sums);

    long long free_time = get_time();
    memcpy(arrayX, arrayX_GPU, sizeof(double) * Nparticles);
    long long arrayX_time = get_time();
    memcpy(arrayY, arrayY_GPU, sizeof(double) * Nparticles);
    long long arrayY_time = get_time();
    memcpy(weights, weights_GPU, sizeof(double) * Nparticles);
    long long back_end_time = get_time();
    printf("GPU Execution: %lf\n", elapsed_time(send_end, back_time));
    printf("FREE TIME: %lf\n", elapsed_time(back_time, free_time));
    printf("TIME TO SEND BACK: %lf\n", elapsed_time(back_time, back_end_time));
    printf("SEND ARRAY X BACK: %lf\n", elapsed_time(free_time, arrayX_time));
    printf("SEND ARRAY Y BACK: %lf\n", elapsed_time(arrayX_time, arrayY_time));
    printf("SEND WEIGHTS BACK: %lf\n", elapsed_time(arrayY_time, back_end_time));

    xe = 0;
    ye = 0;

    for (x = 0; x < Nparticles; x++) {
        xe += arrayX[x] * weights[x];
        ye += arrayY[x] * weights[x];
    }
    printf("XE: %lf\n", xe);
    printf("YE: %lf\n", ye);
    double distance = sqrt(pow((double) (xe - (int) roundDouble(IszY / 2.0)), 2) + pow((double) (ye - (int) roundDouble(IszX / 2.0)), 2));
    printf("%lf\n", distance);

    free(weights_GPU);
    free(arrayY_GPU);
    free(arrayX_GPU);

    free(likelihood);
    free(arrayX);
    free(arrayY);
    free(xj);
    free(yj);
    free(CDF);
    free(ind);
    free(u);
    free(weights);
    free(objxy);
    free(disk);
}

int main(int argc, char *argv[]) {
    char *usage = "double.out -x <dimX> -y <dimY> -z <Nfr> -np <Nparticles>";

    if (argc != 9) {
        printf("%s\n", usage);
        return 0;
    }

    if (strcmp(argv[1], "-x") || strcmp(argv[3], "-y") || strcmp(argv[5], "-z") || strcmp(argv[7], "-np")) {
        printf("%s\n", usage);
        return 0;
    }

    int IszX, IszY, Nfr, Nparticles;

    if (sscanf(argv[2], "%d", &IszX) == EOF) {
        printf("ERROR: dimX input is incorrect");
        return 0;
    }

    if (IszX <= 0) {
        printf("dimX must be > 0\n");
        return 0;
    }

    if (sscanf(argv[4], "%d", &IszY) == EOF) {
        printf("ERROR: dimY input is incorrect");
        return 0;
    }

    if (IszY <= 0) {
        printf("dimY must be > 0\n");
        return 0;
    }

    if (sscanf(argv[6], "%d", &Nfr) == EOF) {
        printf("ERROR: Number of frames input is incorrect");
        return 0;
    }

    if (Nfr <= 0) {
        printf("number of frames must be > 0\n");
        return 0;
    }

    if (sscanf(argv[8], "%d", &Nparticles) == EOF) {
        printf("ERROR: Number of particles input is incorrect");
        return 0;
    }

    if (Nparticles <= 0) {
        printf("Number of particles must be > 0\n");
        return 0;
    }

    int *seed = (int *) malloc(sizeof(int) * Nparticles);
    int i;
    for (i = 0; i < Nparticles; i++)
        seed[i] = (int) time(0) * i;

    unsigned char *I = (unsigned char *) calloc((size_t) IszX * IszY * Nfr, sizeof(unsigned char));
    long long start = get_time();

    videoSequence(I, IszX, IszY, Nfr, seed);
    long long endVideoSequence = get_time();
    printf("VIDEO SEQUENCE TOOK %f\n", elapsed_time(start, endVideoSequence));

    particleFilter(I, IszX, IszY, Nfr, seed, Nparticles);
    long long endParticleFilter = get_time();
    printf("PARTICLE FILTER TOOK %f\n", elapsed_time(endVideoSequence, endParticleFilter));
    printf("ENTIRE PROGRAM TOOK %f\n", elapsed_time(start, endParticleFilter));

    free(seed);
    free(I);
    return 0;
}

