    int neighY = 0;
    int center = radius - 1;
    int diameter = radius * 2 - 1;
    for (x = 0; x < diameter; x++) {
        for (y = 0; y < diameter; y++) {
            if (se[x * diameter + y]) {
                neighbors[neighY * 2] = (int)(y - center);
                neighbors[neighY * 2 + 1] = (int)(x - center);
                neighY++;
            }
        }
    }
}

void videoSequence(unsigned char *I, int IszX, int IszY, int Nfr, int *seed) {
    int k;
    int max_size = IszX * IszY * Nfr;

    int x0 = (int)roundDouble(IszY / 2.0);
    int y0 = (int)roundDouble(IszX / 2.0);
    I[x0 * IszY * Nfr + y0 * Nfr + 0] = 1;

    {
        int xk, yk, pos;
        for (k = 1; k < Nfr; k++) {
            xk = abs(x0 + (k - 1));
            yk = abs(y0 - 2 * (k - 1));
            pos = yk * IszY * Nfr + xk * Nfr + k;
            if (pos >= max_size)
                pos = 0;
            I[pos] = 1;
        }
    }

    {
        unsigned char *newMatrix = (unsigned char *)calloc((size_t)IszX * IszY * Nfr, sizeof(unsigned char));
        int x, y;
        imdilate_disk(I, IszX, IszY, Nfr, 5, newMatrix);
        for (x = 0; x < IszX; x++) {
            for (y = 0; y < IszY; y++) {
                for (k = 0; k < Nfr; k++) {
                    I[x * IszY * Nfr + y * Nfr + k] = newMatrix[x * IszY * Nfr + y * Nfr + k];
                }
            }
        }
        free(newMatrix);
    }

    setIf(0, 100, I, &IszX, &IszY, &Nfr);
    setIf(1, 228, I, &IszX, &IszY, &Nfr);
    addNoise(I, &IszX, &IszY, &Nfr, seed);
}

int findIndex(double *CDF, int lengthCDF, double value) {
    int index = -1;
    int x;
    for (x = 0; x < lengthCDF; x++) {
        if (CDF[x] >= value) {
            index = x;
            break;
        }
    }
    if (index == -1) {
        return lengthCDF - 1;
    }
    return index;
}

void particleFilter(unsigned char *I, int IszX, int IszY, int Nfr, int *seed, int Nparticles) {
    int max_size = IszX * IszY * Nfr;
    double xe = roundDouble(IszY / 2.0);
    double ye = roundDouble(IszX / 2.0);

    int radius = 5;
    int diameter = radius * 2 - 1;
    int *disk = (int *)malloc((size_t)diameter * diameter * sizeof(int));
    int countOnes = 0;
    int x, y;

    strelDisk(disk, radius);
    for (x = 0; x < diameter; x++) {
        for (y = 0; y < diameter; y++) {
            if (disk[x * diameter + y] == 1)
                countOnes++;
        }
    }

    {
        int *objxy = (int *)malloc((size_t)countOnes * 2 * sizeof(int));
        double *weights = (double *)malloc((size_t)Nparticles * sizeof(double));
        double *likelihood = (double *)malloc((size_t)Nparticles * sizeof(double));
        double *arrayX = (double *)malloc((size_t)Nparticles * sizeof(double));
        double *arrayY = (double *)malloc((size_t)Nparticles * sizeof(double));
        double *xj = (double *)malloc((size_t)Nparticles * sizeof(double));
        double *yj = (double *)malloc((size_t)Nparticles * sizeof(double));
        double *CDF = (double *)malloc((size_t)Nparticles * sizeof(double));
        int *ind = (int *)malloc((size_t)countOnes * Nparticles * sizeof(int));
        double *u = (double *)malloc((size_t)Nparticles * sizeof(double));

        double *arrayX_GPU = (double *)malloc((size_t)Nparticles * sizeof(double));
        double *arrayY_GPU = (double *)malloc((size_t)Nparticles * sizeof(double));
        double *xj_GPU = (double *)malloc((size_t)Nparticles * sizeof(double));
        double *yj_GPU = (double *)malloc((size_t)Nparticles * sizeof(double));
        double *CDF_GPU = (double *)malloc((size_t)Nparticles * sizeof(double));
        double *likelihood_GPU = (double *)malloc((size_t)Nparticles * sizeof(double));
        unsigned char *I_GPU = (unsigned char *)malloc((size_t)IszX * IszY * Nfr * sizeof(unsigned char));
        double *weights_GPU = (double *)malloc((size_t)Nparticles * sizeof(double));
        int *objxy_GPU = (int *)malloc((size_t)2 * countOnes * sizeof(int));
        int *ind_GPU = (int *)malloc((size_t)countOnes * Nparticles * sizeof(int));
        double *u_GPU = (double *)malloc((size_t)Nparticles * sizeof(double));
        int *seed_GPU = (int *)malloc((size_t)Nparticles * sizeof(int));
        double *partial_sums = (double *)malloc((size_t)Nparticles * sizeof(double));

        int num_blocks;
        int k;

        getneighbors(disk, countOnes, objxy, radius);

        for (x = 0; x < Nparticles; x++) {
            weights[x] = 1 / ((double)(Nparticles));
            xj[x] = xe;
            yj[x] = ye;
        }

        {
            long long send_start = get_time();
            memcpy(I_GPU, I, (size_t)IszX * IszY * Nfr * sizeof(unsigned char));
            memcpy(objxy_GPU, objxy, (size_t)2 * countOnes * sizeof(int));
            memcpy(weights_GPU, weights, (size_t)Nparticles * sizeof(double));
            memcpy(xj_GPU, xj, (size_t)Nparticles * sizeof(double));
            memcpy(yj_GPU, yj, (size_t)Nparticles * sizeof(double));
            memcpy(seed_GPU, seed, (size_t)Nparticles * sizeof(int));
            memset(likelihood_GPU, 0, (size_t)Nparticles * sizeof(double));
            long long send_end = get_time();
            printf("TIME TO SEND TO GPU: %f\n", elapsed_time(send_start, send_end));

            num_blocks = (int)ceil((double)Nparticles / (double)threads_per_block);

            for (k = 1; k < Nfr; k++) {
                double sumWeights;
                double u1;

                #pragma omp parallel for private(y)
                for (x = 0; x < Nparticles; x++) {
                    int indX, indY;
                    arrayX_GPU[x] = xj_GPU[x];
                    arrayY_GPU[x] = yj_GPU[x];
                    weights_GPU[x] = 1 / ((double)(Nparticles));

                    arrayX_GPU[x] = arrayX_GPU[x] + 1.0 + 5.0 * randn(seed_GPU, x);
                    arrayY_GPU[x] = arrayY_GPU[x] - 2.0 + 2.0 * randn(seed_GPU, x);

                    for (y = 0; y < countOnes; y++) {
                        indX = (int)roundDouble(arrayX_GPU[x]) + objxy_GPU[y * 2 + 1];
                        indY = (int)roundDouble(arrayY_GPU[x]) + objxy_GPU[y * 2];
                        ind_GPU[x * countOnes + y] = abs(indX * IszY * Nfr + indY * Nfr + k);
                        if (ind_GPU[x * countOnes + y] >= max_size)
                            ind_GPU[x * countOnes + y] = 0;
                    }

                    likelihood_GPU[x] = calcLikelihoodSum(I_GPU, ind_GPU, countOnes, x);
                    likelihood_GPU[x] = likelihood_GPU[x] / countOnes;
                    weights_GPU[x] = weights_GPU[x] * exp(likelihood_GPU[x]);
                }

                for (x = 0; x < num_blocks; x++) {
                    partial_sums[x] = 0.0;
                }

                #pragma omp parallel for reduction(+:sumWeights)
                for (x = 0; x < Nparticles; x++) {
                    sumWeights += weights_GPU[x];
                }

                partial_sums[0] = sumWeights;

                #pragma omp parallel for
                for (x = 0; x < Nparticles; x++) {
                    weights_GPU[x] = weights_GPU[x] / partial_sums[0];
                }

                cdfCalc(CDF_GPU, weights_GPU, Nparticles);
                u_GPU[0] = (1 / ((double)(Nparticles))) * randu(seed_GPU, 0);
                u1 = u_GPU[0];

                #pragma omp parallel for
                for (x = 0; x < Nparticles; x++) {
                    u_GPU[x] = u1 + x / ((double)(Nparticles));
                }

                #pragma omp parallel for
                for (x = 0; x < Nparticles; x++) {
                    int index = -1;
                    int j;
                    for (j = 0; j < Nparticles; j++) {
                        if (CDF_GPU[j] >= u_GPU[x]) {
                            index = j;
                            break;
                        }
                    }
                    if (index == -1) {
                        index = Nparticles - 1;
                    }
                    xj_GPU[x] = arrayX_GPU[index];
                    yj_GPU[x] = arrayY_GPU[index];
                }
            }

            {
                long long back_time = get_time();
                long long free_time = get_time();
                memcpy(arrayX, arrayX_GPU, (size_t)Nparticles * sizeof(double));
                long long arrayX_time = get_time();
                memcpy(arrayY, arrayY_GPU, (size_t)Nparticles * sizeof(double));
                long long arrayY_time = get_time();
                memcpy(weights, weights_GPU, (size_t)Nparticles * sizeof(double));
                long long back_end_time = get_time();

                printf("GPU Execution: %lf\n", elapsed_time(send_end, back_time));
                printf("FREE TIME: %lf\n", elapsed_time(back_time, free_time));
                printf("TIME TO SEND BACK: %lf\n", elapsed_time(back_time, back_end_time));
                printf("SEND ARRAY X BACK: %lf\n", elapsed_time(free_time, arrayX_time));
                printf("SEND ARRAY Y BACK: %lf\n", elapsed_time(arrayX_time, arrayY_time));
                printf("SEND WEIGHTS BACK: %lf\n", elapsed_time(arrayY_time, back_end_time));
            }
        }

        xe = 0;
        ye = 0;

        for (x = 0; x < Nparticles; x++) {
            xe += arrayX[x] * weights[x];
            ye += arrayY[x] * weights[x];
        }

        printf("XE: %lf\n", xe);
        printf("YE: %lf\n", ye);
        {
            double distance = sqrt(pow((double)(xe - (int)roundDouble(IszY / 2.0)), 2) +
                                   pow((double)(ye - (int)roundDouble(IszX / 2.0)), 2));
            printf("%lf\n", distance);
        }

        free(weights_GPU);
        free(arrayY_GPU);
        free(arrayX_GPU);
        free(xj_GPU);
        free(yj_GPU);
        free(CDF_GPU);
        free(u_GPU);
        free(likelihood_GPU);
        free(I_GPU);
        free(objxy_GPU);
        free(ind_GPU);
        free(seed_GPU);
        free(partial_sums);

        free(objxy);
        free(likelihood);
        free(arrayX);
        free(arrayY);
        free(xj);
        free(yj);
        free(CDF);
        free(ind);
        free(u);
        free(weights);
    }

    free(disk);
}

int main(int argc, char *argv[]) {
    char *usage = "double.out -x <dimX> -y <dimY> -z <Nfr> -np <Nparticles>";

    if (argc != 9) {
        printf("%s\n", usage);
        return 0;
    }

    if (strcmp(argv[1], "-x") || strcmp(argv[3], "-y") || strcmp(argv[5], "-z") || strcmp(argv[7], "-np")) {
        printf("%s\n", usage);
        return 0;
    }

    {
        int IszX, IszY, Nfr, Nparticles;
        int *seed;
        int i;
        unsigned char *I;
        long long start, endVideoSequence, endParticleFilter;

        if (sscanf(argv[2], "%d", &IszX) == EOF) {
            printf("ERROR: dimX input is incorrect");
            return 0;
        }
        if (IszX <= 0) {
            printf("dimX must be > 0\n");
            return 0;
        }

        if (sscanf(argv[4], "%d", &IszY) == EOF) {
            printf("ERROR: dimY input is incorrect");
            return 0;
        }
        if (IszY <= 0) {
            printf("dimY must be > 0\n");
            return 0;
        }

        if (sscanf(argv[6], "%d", &Nfr) == EOF) {
            printf("ERROR: Number of frames input is incorrect");
            return 0;
        }
        if (Nfr <= 0) {
            printf("number of frames must be > 0\n");
            return 0;
        }

        if (sscanf(argv[8], "%d", &Nparticles) == EOF) {
            printf("ERROR: Number of particles input is incorrect");
            return 0;
        }
        if (Nparticles <= 0) {
            printf("Number of particles must be > 0\n");
            return 0;
        }

        seed = (int *)malloc((size_t)Nparticles * sizeof(int));
        for (i = 0; i < Nparticles; i++)
            seed[i] = (int)time(0) * i;

        I = (unsigned char *)calloc((size_t)IszX * IszY * Nfr, sizeof(unsigned char));

        start = get_time();
        videoSequence(I, IszX, IszY, Nfr, seed);
        endVideoSequence = get_time();
        printf("VIDEO SEQUENCE TOOK %f\n", elapsed_time(start, endVideoSequence));

        particleFilter(I, IszX, IszY, Nfr, seed, Nparticles);
        endParticleFilter = get_time();
        printf("PARTICLE FILTER TOOK %f\n", elapsed_time(endVideoSequence, endParticleFilter));
        printf("ENTIRE PROGRAM TOOK %f\n", elapsed_time(start, endParticleFilter));

        free(seed);
        free(I);
    }

    return 0;
}

