#define MIN(a, b) ((a) <= (b) ? (a) : (b))

int calc_path(int* gpuWall, int* gpuResult[2], int rows, int cols,
              int pyramid_height, int blockCols, int borderCols)
{
    (void)blockCols;
    (void)borderCols;

    int src = 1, dst = 0;
    int* tempA = new int[cols];
    int* tempB = new int[cols];

    for (int t = 0; t < rows - 1; t += pyramid_height) {
        int temp = src;
        src = dst;
        dst = temp;

        int iteration = MIN(pyramid_height, rows - t - 1);
        int* prev = gpuResult[src];

        for (int i = 0; i < iteration; i++) {
            int* curr;
            if (i == iteration - 1) {
                curr = gpuResult[dst];
            } else if (i % 2 == 0) {
                curr = tempA;
            } else {
                curr = tempB;
            }

            int* wallRow = gpuWall + (t + i) * cols;

#pragma omp parallel for schedule(static)
            for (int x = 0; x < cols; x++) {
                int left = prev[(x == 0) ? 0 : (x - 1)];
                int up = prev[x];
                int right = prev[(x == cols - 1) ? (cols - 1) : (x + 1)];
                int shortest = MIN(left, up);
                shortest = MIN(shortest, right);
                curr[x] = shortest + wallRow[x];
            }

            prev = curr;
        }
    }

    delete[] tempA;
    delete[] tempB;
    return dst;
}

