static void srad_omp_1(
	float *E_C,
	float *W_C,
	float *N_C,
	float *S_C,
	float *J,
	float *C,
	int cols,
	int rows,
	float q0sqr)
{
#pragma omp parallel for collapse(2) schedule(static)
	for (int i = 0; i < rows; i++) {
		for (int j = 0; j < cols; j++) {
			int index = i * cols + j;

			int iN = (i == 0) ? 0 : (i - 1);
			int iS = (i == rows - 1) ? (rows - 1) : (i + 1);
			int jW = (j == 0) ? 0 : (j - 1);
			int jE = (j == cols - 1) ? (cols - 1) : (j + 1);

			float jc = J[index];
			float n = J[iN * cols + j] - jc;
			float s = J[iS * cols + j] - jc;
			float w = J[i * cols + jW] - jc;
			float e = J[i * cols + jE] - jc;

			float g2 = (n * n + s * s + w * w + e * e) / (jc * jc);
			float l = (n + s + w + e) / jc;

			float num = (0.5 * g2) - ((1.0 / 16.0) * (l * l));
			float den = 1 + (.25 * l);
			float qsqr = num / (den * den);

			den = (qsqr - q0sqr) / (q0sqr * (1 + q0sqr));
			float c = 1.0 / (1.0 + den);

			if (c < 0) {
				C[index] = 0;
			} else if (c > 1) {
				C[index] = 1;
			} else {
				C[index] = c;
			}

			E_C[index] = e;
			W_C[index] = w;
			S_C[index] = s;
			N_C[index] = n;
		}
	}
}

static void srad_omp_2(
