    for (long kk = 0; kk < points->num; kk++) {
      points->p[kk].assign = kk;
      points->p[kk].cost = 0;
    }
    cost = 0;
    *kfinal = k;
    return cost;
  }

  shuffle(points);
  cost = pspeedy(points, z, &k, pid, barrier);

#ifdef PRINTINFO
  printf("thread %d: Finished first call to speedy, cost=%lf, k=%i\n", pid, cost, (int)k);
#endif
  i = 0;

  while ((k < kmin) && (i < SP)) {
    cost = pspeedy(points, z, &k, pid, barrier);
    i++;
  }

#ifdef PRINTINFO
  printf("thread %d: second call to speedy, cost=%lf, k=%d\n", pid, cost, (int)k);
#endif

  while (k < kmin) {
#ifdef PRINTINFO
    printf("%lf %lf\n", loz, hiz);
    printf("Speedy indicates we should try lower z\n");
#endif
    if (i >= SP) {
      hiz = z;
      z = (hiz + loz) / 2.0;
      i = 0;
    }
    shuffle(points);
    cost = pspeedy(points, z, &k, pid, barrier);
    i++;
  }

  numfeasible = selectfeasible_fast(points, &feasible, kmin, pid, barrier);
  for (int ii = 0; ii < points->num; ii++) {
    is_center[points->p[ii].assign] = true;
  }

  while (1) {
#ifdef PRINTINFO
    printf("loz = %lf, hiz = %lf\n", loz, hiz);
    printf("Running Local Search...\n");
#endif

    lastcost = cost;
    cost = pFL(points, feasible, numfeasible,
               z, &k, kmax, cost, (long)(ITER * kmax * log((float)kmax)), 0.1, pid, barrier);

    if (((k <= (1.1) * kmax) && (k >= (0.9) * kmin)) ||
        ((k <= kmax + 2) && (k >= kmin - 2))) {
#ifdef PRINTINFO
      printf("Trying a more accurate local search...\n");
#endif
      cost = pFL(points, feasible, numfeasible,
                 z, &k, kmax, cost, (long)(ITER * kmax * log((float)kmax)), 0.001, pid, barrier);
    }

    if (k > kmax) {
      loz = z;
      z = (hiz + loz) / 2.0;
      cost += (z - loz) * k;
    }
    if (k < kmin) {
      hiz = z;
      z = (hiz + loz) / 2.0;
      cost += (z - hiz) * k;
    }

    if (((k <= kmax) && (k >= kmin)) || ((loz >= (0.999) * hiz))) {
      break;
    }
