  *kfinal = k;
  return cost;
}

int contcenters(Points *points) {
  long i, ii;
  float relweight;

  for (i = 0; i < points->num; i++) {
    if (points->p[i].assign != i) {
      relweight = points->p[points->p[i].assign].weight + points->p[i].weight;
      relweight = points->p[i].weight / relweight;
      for (ii = 0; ii < points->dim; ii++) {
        points->p[points->p[i].assign].coord[ii] *= 1.0 - relweight;
        points->p[points->p[i].assign].coord[ii] +=
            points->p[i].coord[ii] * relweight;
      }
      points->p[points->p[i].assign].weight += points->p[i].weight;
    }
  }

  return 0;
}

void copycenters(Points *points, Points* centers, long* centerIDs, long offset) {
  long i;
  long k;

  bool *is_a_median = (bool *)calloc(points->num, sizeof(bool));

  for (i = 0; i < points->num; i++) {
    is_a_median[points->p[i].assign] = 1;
  }

  k = centers->num;

  for (i = 0; i < points->num; i++) {
    if (is_a_median[i]) {
      memcpy(centers->p[k].coord, points->p[i].coord, points->dim * sizeof(float));
      centers->p[k].weight = points->p[i].weight;
      centerIDs[k] = i + offset;
      k++;
    }
  }

  centers->num = k;

  free(is_a_median);
}

void localSearch(Points* points, long kmin, long kmax, long* kfinal) {
#ifdef PROFILE
  double t1 = gettime();
#endif

  pkmedian(points, kmin, kmax, kfinal, 0, NULL);

#ifdef PROFILE
  double t2 = gettime();
  time_local_search += t2 - t1;
#endif
}

void outcenterIDs(Points* centers, long* centerIDs, char* outfile) {
  FILE* fp = fopen(outfile, "w");
  if (fp == NULL) {
    fprintf(stderr, "error opening %s\n", outfile);
    exit(1);
  }
  int* is_a_median = (int*)calloc(centers->num, sizeof(int));
  for (int i = 0; i < centers->num; i++) {
    is_a_median[centers->p[i].assign] = 1;
  }

  for (int i = 0; i < centers->num; i++) {
    if (is_a_median[i]) {
      fprintf(fp, "%u\n", centerIDs[i]);
      fprintf(fp, "%lf\n", centers->p[i].weight);
      for (int k = 0; k < centers->dim; k++) {
        fprintf(fp, "%lf ", centers->p[i].coord[k]);
      }
      fprintf(fp, "\n\n");
    }
  }
  fclose(fp);
  free(is_a_median);
}

void streamCluster(PStream* stream,
                   long kmin, long kmax, int dim,
                   long chunksize, long centersize, char* outfile) {
  float* block = (float*)malloc(chunksize * dim * sizeof(float));
  float* centerBlock = (float*)malloc(centersize * dim * sizeof(float));
  long* centerIDs = (long*)malloc(centersize * dim * sizeof(long));

  if (block == NULL) {
    fprintf(stderr, "not enough memory for a chunk!\n");
    exit(1);
  }

  Points points;
  points.dim = dim;
  points.num = chunksize;
  points.p = (Point *)malloc(chunksize * sizeof(Point));
  for (int i = 0; i < chunksize; i++) {
    points.p[i].coord = &block[i * dim];
  }

  Points centers;
  centers.dim = dim;
  centers.p = (Point *)malloc(centersize * sizeof(Point));
  centers.num = 0;

  for (int i = 0; i < centersize; i++) {
    centers.p[i].coord = &centerBlock[i * dim];
    centers.p[i].weight = 1.0;
  }

  long IDoffset = 0;
  long kfinal;
  while (1) {
    size_t numRead = stream->read(block, dim, chunksize);
    fprintf(stderr, "read %d points\n", (int)numRead);

    if (stream->ferror() || numRead < (unsigned int)chunksize && !stream->feof()) {
      fprintf(stderr, "error reading data!\n");
      exit(1);
    }

    points.num = numRead;
    for (int i = 0; i < points.num; i++) {
      points.p[i].weight = 1.0;
    }

    switch_membership = (bool*)malloc(points.num * sizeof(bool));
    is_center = (bool*)calloc(points.num, sizeof(bool));
    center_table = (int*)malloc(points.num * sizeof(int));

    localSearch(&points, kmin, kmax, &kfinal);

    fprintf(stderr, "finish local search\n");

    contcenters(&points);
    isCoordChanged = true;

    if (kfinal + centers.num > centersize) {
      fprintf(stderr, "oops! no more space for centers\n");
      exit(1);
    }

#ifdef PRINTINFO
    printf("finish cont center\n");
#endif

    copycenters(&points, &centers, centerIDs, IDoffset);
    IDoffset += numRead;

#ifdef PRINTINFO
    printf("finish copy centers\n");
#endif

    free(is_center);
    free(switch_membership);
    free(center_table);

    if (stream->feof()) {
      break;
    }
  }

  switch_membership = (bool*)malloc(centers.num * sizeof(bool));
  is_center = (bool*)calloc(centers.num, sizeof(bool));
  center_table = (int*)malloc(centers.num * sizeof(int));

  localSearch(&centers, kmin, kmax, &kfinal);
  contcenters(&centers);
  outcenterIDs(&centers, centerIDs, outfile);

  free(is_center);
  free(switch_membership);
  free(center_table);
  free(points.p);
  free(centers.p);
  free(block);
  free(centerBlock);
  free(centerIDs);
}

int main(int argc, char **argv) {
  char *outfilename = new char[MAXNAMESIZE];
  char *infilename = new char[MAXNAMESIZE];
  long kmin, kmax, n, chunksize, clustersize;
  int dim;
#ifdef PARSEC_VERSION
#define __PARSEC_STRING(x) #x
#define __PARSEC_XSTRING(x) __PARSEC_STRING(x)
  printf("PARSEC Benchmark Suite Version " __PARSEC_XSTRING(PARSEC_VERSION) "\n");
  fflush(NULL);
#else
  printf("PARSEC Benchmark Suite\n");
  fflush(NULL);
#endif
#ifdef ENABLE_PARSEC_HOOKS
  __parsec_bench_begin(__parsec_streamcluster);
#endif

  if (argc < 10) {
    fprintf(stderr, "usage: %s k1 k2 d n chunksize clustersize infile outfile nproc\n",
            argv[0]);
    fprintf(stderr, "  k1:          Min. number of centers allowed\n");
    fprintf(stderr, "  k2:          Max. number of centers allowed\n");
    fprintf(stderr, "  d:           Dimension of each data point\n");
    fprintf(stderr, "  n:           Number of data points\n");
    fprintf(stderr, "  chunksize:   Number of data points to handle per step\n");
    fprintf(stderr, "  clustersize: Maximum number of intermediate centers\n");
    fprintf(stderr, "  infile:      Input file (if n<=0)\n");
    fprintf(stderr, "  outfile:     Output file\n");
    fprintf(stderr, "  nproc:       Number of threads to use\n");
    fprintf(stderr, "\n");
    fprintf(stderr, "if n > 0, points will be randomly generated instead of reading from infile.\n");
    exit(1);
  }
  kmin = atoi(argv[1]);
  kmax = atoi(argv[2]);
  dim = atoi(argv[3]);
  n = atoi(argv[4]);
  chunksize = atoi(argv[5]);
  clustersize = atoi(argv[6]);
  strcpy(infilename, argv[7]);
  strcpy(outfilename, argv[8]);
  nproc = atoi(argv[9]);

  omp_set_num_threads(nproc);
  srand48(SEED);
  PStream* stream;
  if (n > 0) {
    stream = new SimStream(n);
  } else {
    stream = new FileStream(infilename);
  }

  double t1 = gettime();

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_roi_begin();
#endif

  serial_t = 0.0;
  cpu_to_gpu_t = 0.0;
  gpu_to_cpu_t = 0.0;
  alloc_t = 0.0;
  free_t = 0.0;
  kernel_t = 0.0;

  isCoordChanged = false;

  streamCluster(stream, kmin, kmax, dim, chunksize, clustersize, outfilename);

  freeDevMem();
  freeHostMem();

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_roi_end();
#endif

  double t2 = gettime();

  printf("time = %lfs\n", t2 - t1);

  delete stream;

#ifdef PROFILE
  printf("time pgain = %lfs\n", time_gain);
  printf("time pgain_dist = %lfs\n", time_gain_dist);
  printf("time pgain_init = %lfs\n", time_gain_init);
  printf("time pselect = %lfs\n", time_select_feasible);
  printf("time pspeedy = %lfs\n", time_speedy);
  printf("time pshuffle = %lfs\n", time_shuffle);
  printf("time localSearch = %lfs\n", time_local_search);
  printf("\n\n");
  printf("====CUDA Timing info (pgain)====\n");
  printf("time serial = %lfs\n", serial_t / 1000);
  printf("time CPU to GPU memory copy = %lfs\n", cpu_to_gpu_t / 1000);
  printf("time GPU to CPU memory copy back = %lfs\n", gpu_to_cpu_t / 1000);
  printf("time GPU malloc = %lfs\n", alloc_t / 1000);
  printf("time GPU free = %lfs\n", free_t / 1000);
  printf("time kernel = %lfs\n", kernel_t / 1000);
#endif

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_bench_end();
#endif

  delete[] outfilename;
  delete[] infilename;
  return 0;
}

#include <stdio.h>
#include <iostream>
#include <fstream>
#include <stdlib.h>
#include <sys/time.h>
#include <string.h>
#include <assert.h>
#include <math.h>
#include <sys/resource.h>
#include <limits.h>
#include <omp.h>

#ifdef ENABLE_PARSEC_HOOKS
#include <hooks.h>
#endif

using namespace std;

typedef struct {
  float weight;
  float *coord;
  long assign;
  float cost;
} Point;

typedef struct {
  long num;
  int dim;
  Point *p;
} Points;

class PStream {
public:
  virtual size_t read(float* dest, int dim, int num) = 0;
  virtual int ferror() = 0;
  virtual int feof() = 0;
  virtual ~PStream() {
  }
};

class SimStream : public PStream {
public:
  SimStream(long n_) {
    n = n_;
  }
  size_t read(float* dest, int dim, int num) override {
    size_t count = 0;
    for (int i = 0; i < num && n > 0; i++) {
      for (int k = 0; k < dim; k++) {
        dest[i * dim + k] = lrand48() / (float)INT_MAX;
      }
      n--;
      count++;
    }
    return count;
  }
  int ferror() override {
    return 0;
  }
  int feof() override {
    return n <= 0;
  }
  ~SimStream() override {
  }
private:
  long n;
};

class FileStream : public PStream {
public:
  FileStream(char* filename) {
    fp = fopen(filename, "rb");
    if (fp == NULL) {
      fprintf(stderr, "error opening file %s\n.", filename);
      exit(1);
    }
  }
  size_t read(float* dest, int dim, int num) override {
    return std::fread(dest, sizeof(float) * dim, num, fp);
  }
  int ferror() override {
    return std::ferror(fp);
  }
  int feof() override {
    return std::feof(fp);
  }
  ~FileStream() override {
    printf("closing file stream\n");
    fclose(fp);
  }
private:
  FILE* fp;
};

#define MAXNAMESIZE 1024
#define SEED 1
#define SP 1
#define ITER 3
#define PROFILE

static bool *switch_membership;
static bool *is_center;
static int  *center_table;
static int nproc;
bool isCoordChanged;

double serial_t;
double cpu_to_gpu_t;
double gpu_to_cpu_t;
double alloc_t;
double kernel_t;
double free_t;

#ifdef PROFILE
double time_local_search = 0.0;
double time_speedy = 0.0;
double time_select_feasible = 0.0;
double time_gain = 0.0;
double time_shuffle = 0.0;
double time_gain_dist = 0.0;
double time_gain_init = 0.0;
#endif

static float *work_mem_h = NULL;
static float *coord_h = NULL;
static size_t coord_h_capacity = 0;
static int iter = 0;

void inttofile(int data, char *filename) {
  FILE *fp = fopen(filename, "w");
  fprintf(fp, "%d ", data);
  fclose(fp);
}

double gettime() {
  struct timeval t;
  gettimeofday(&t, NULL);
  return t.tv_sec + t.tv_usec * 1e-6;
}

int isIdentical(float *i, float *j, int D) {
  int a = 0;
  int equal = 1;
  while (equal && a < D) {
    if (i[a] != j[a]) equal = 0;
    else a++;
  }
  if (equal) return 1;
  else return 0;
}

static int floatcomp(const void *i, const void *j) {
  float a, b;
  a = *(float *)(i);
  b = *(float *)(j);
  if (a > b) return (1);
  if (a < b) return (-1);
  return (0);
}

void shuffle(Points *points) {
#ifdef PROFILE
  double t1 = gettime();
#endif
  long i, j;
  Point temp;
  for (i = 0; i < points->num - 1; i++) {
    j = (lrand48() % (points->num - i)) + i;
    temp = points->p[i];
    points->p[i] = points->p[j];
    points->p[j] = temp;
  }
#ifdef PROFILE
  double t2 = gettime();
  time_shuffle += t2 - t1;
#endif
}

void intshuffle(int *intarray, int length) {
#ifdef PROFILE
  double t1 = gettime();
#endif
  long i, j;
  int temp;
  for (i = 0; i < length; i++) {
    j = (lrand48() % (length - i)) + i;
    temp = intarray[i];
    intarray[i] = intarray[j];
    intarray[j] = temp;
  }
#ifdef PROFILE
  double t2 = gettime();
  time_shuffle += t2 - t1;
#endif
}

float dist(Point p1, Point p2, int dim) {
  int i;
  float result = 0.0;
  for (i = 0; i < dim; i++)
    result += (p1.coord[i] - p2.coord[i]) * (p1.coord[i] - p2.coord[i]);
  return result;
}

static inline double elapsed_ms(double t1, double t2) {
  return (t2 - t1) * 1000.0;
}

static void ensureCoordCapacity(int num, int dim) {
  size_t need = (size_t)num * (size_t)dim;
  if (need > coord_h_capacity) {
    free(coord_h);
    coord_h = (float*)malloc(need * sizeof(float));
    coord_h_capacity = need;
  }
}

void allocDevMem(int, int) {
}

void allocHostMem(int num, int dim) {
  ensureCoordCapacity(num, dim);
}

void freeDevMem() {
}

void freeHostMem() {
  free(coord_h);
  coord_h = NULL;
  coord_h_capacity = 0;
}

static inline float d_dist(int p1, int p2, int num, int dim, float *coord) {
  float retval = 0.0f;
  for (int i = 0; i < dim; i++) {
    float tmp = coord[(i * num) + p1] - coord[(i * num) + p2];
    retval += tmp * tmp;
  }
  return retval;
}

float pgain(long x, Points *points, float z, long int *numcenters, int kmax,
            bool *is_center_arr, int *center_table_arr, bool *switch_membership_arr, bool coordChanged,
            double *serial_t_acc, double *cpu_to_gpu_t_acc, double *gpu_to_cpu_t_acc,
            double *alloc_t_acc, double *kernel_t_acc, double *free_t_acc) {
  double t1, t2;

  int stride = (int)(*numcenters) + 1;
  int K = (int)(*numcenters);
  int num = (int)points->num;
  int dim = points->dim;
  int nThread = num;

  t1 = gettime();
  work_mem_h = (float*)malloc((size_t)stride * (size_t)(nThread + 1) * sizeof(float));
  memset(work_mem_h, 0, (size_t)stride * (size_t)(nThread + 1) * sizeof(float));

  if (iter == 0) {
    allocHostMem(num, dim);
  } else {
    ensureCoordCapacity(num, dim);
  }

  int count = 0;
  for (int i = 0; i < num; i++) {
    if (is_center_arr[i]) {
      center_table_arr[i] = count++;
    }
  }

  if (coordChanged || iter == 0) {
    for (int i = 0; i < dim; i++) {
      for (int j = 0; j < num; j++) {
        coord_h[(num * i) + j] = points->p[j].coord[i];
      }
    }
  }
  t2 = gettime();
  *serial_t_acc += elapsed_ms(t1, t2);

  t1 = gettime();
  t2 = gettime();
  *alloc_t_acc += elapsed_ms(t1, t2);

  t1 = gettime();
  memset(switch_membership_arr, 0, (size_t)num * sizeof(bool));
  t2 = gettime();
  *cpu_to_gpu_t_acc += elapsed_ms(t1, t2);

  t1 = gettime();
#pragma omp parallel for schedule(static) num_threads(nproc)
  for (int tid = 0; tid < num; tid++) {
    float *lower = &work_mem_h[(size_t)tid * stride];
    float x_cost = d_dist(tid, (int)x, num, dim, coord_h) * points->p[tid].weight;

    if (x_cost < points->p[tid].cost) {
      switch_membership_arr[tid] = true;
      lower[K] += x_cost - points->p[tid].cost;
    } else {
      lower[center_table_arr[points->p[tid].assign]] += points->p[tid].cost - x_cost;
    }
  }
  t2 = gettime();
  *kernel_t_acc += elapsed_ms(t1, t2);

  t1 = gettime();
  t2 = gettime();
  *gpu_to_cpu_t_acc += elapsed_ms(t1, t2);

  t1 = gettime();
  int number_of_centers_to_close = 0;
  float gl_cost_of_opening_x = z;
  float *gl_lower = &work_mem_h[(size_t)stride * nThread];

  for (int i = 0; i < num; i++) {
    if (is_center_arr[i]) {
      float low = z;
      for (int j = 0; j < num; j++) {
        low += work_mem_h[(size_t)j * stride + center_table_arr[i]];
      }

      gl_lower[center_table_arr[i]] = low;

      if (low > 0) {
        ++number_of_centers_to_close;
        work_mem_h[(size_t)i * stride + K] -= low;
      }
    }
    gl_cost_of_opening_x += work_mem_h[(size_t)i * stride + K];
  }

  if (gl_cost_of_opening_x < 0) {
    for (int i = 0; i < num; i++) {
      bool close_center = gl_lower[center_table_arr[points->p[i].assign]] > 0;
      if (switch_membership_arr[i] || close_center) {
        points->p[i].cost = dist(points->p[i], points->p[x], dim) * points->p[i].weight;
        points->p[i].assign = x;
      }
    }

    for (int i = 0; i < num; i++) {
      if (is_center_arr[i] && gl_lower[center_table_arr[i]] > 0) {
        is_center_arr[i] = false;
      }
    }

    if (x >= 0 && x < num) {
      is_center_arr[x] = true;
    }
    *numcenters = *numcenters + 1 - number_of_centers_to_close;
  } else {
    gl_cost_of_opening_x = 0;
  }

  free(work_mem_h);
  work_mem_h = NULL;
  t2 = gettime();
  *serial_t_acc += elapsed_ms(t1, t2);

  t1 = gettime();
  t2 = gettime();
  *free_t_acc += elapsed_ms(t1, t2);

  iter++;
  return -gl_cost_of_opening_x;
}

float pspeedy(Points *points, float z, long *kcenter) {
#ifdef PROFILE
  double t1 = gettime();
#endif

  for (int k = 0; k < points->num; k++) {
    float distance = dist(points->p[k], points->p[0], points->dim);
    points->p[k].cost = distance * points->p[k].weight;
    points->p[k].assign = 0;
  }

  *kcenter = 1;

  for (int i = 1; i < points->num; i++) {
    bool to_open = ((float)lrand48() / (float)INT_MAX) < (points->p[i].cost / z);
    if (to_open) {
      (*kcenter)++;
      for (int k = 0; k < points->num; k++) {
        float distance = dist(points->p[i], points->p[k], points->dim);
        if (distance * points->p[k].weight < points->p[k].cost) {
          points->p[k].cost = distance * points->p[k].weight;
          points->p[k].assign = i;
        }
      }
    }
  }

  float totalcost = z * (*kcenter);
  for (int k = 0; k < points->num; k++) {
    totalcost += points->p[k].cost;
  }

#ifdef PROFILE
  double t2 = gettime();
  time_speedy += t2 - t1;
#endif
  return totalcost;
}

float pFL(Points *points, int *feasible, int numfeasible,
          float z, long *k, int kmax, float cost, long iter_count, float e) {
  long i;
  long x;
  float change;
  long numberOfPoints;

  change = cost;

  while (change / cost > 1.0 * e) {
    change = 0.0;
    numberOfPoints = points->num;

    intshuffle(feasible, numfeasible);

    for (i = 0; i < iter_count; i++) {
      x = i % numfeasible;
      change += pgain(feasible[x], points, z, k, kmax, is_center, center_table,
                      switch_membership, isCoordChanged,
                      &serial_t, &cpu_to_gpu_t, &gpu_to_cpu_t, &alloc_t, &kernel_t, &free_t);
    }

    cost -= change;
  }
  return cost;
}

int selectfeasible_fast(Points *points, int **feasible, int kmin) {
#ifdef PROFILE
  double t1 = gettime();
#endif

  int numfeasible = (int)points->num;
  if (numfeasible > (ITER * kmin * log((float)kmin)))
    numfeasible = (int)(ITER * kmin * log((float)kmin));
  *feasible = (int *)malloc((size_t)numfeasible * sizeof(int));

  float* accumweight;
  float totalweight;

  long k1 = 0;
  long k2 = numfeasible;

  float w;
  int l, r, k;

  if (numfeasible == points->num) {
    for (int i = (int)k1; i < k2; i++)
      (*feasible)[i] = i;
#ifdef PROFILE
    double t2 = gettime();
    time_select_feasible += t2 - t1;
#endif
    return numfeasible;
  }

  accumweight = (float*)malloc((size_t)points->num * sizeof(float));
  accumweight[0] = points->p[0].weight;
  totalweight = 0;
  for (int i = 1; i < points->num; i++) {
    accumweight[i] = accumweight[i - 1] + points->p[i].weight;
  }
  totalweight = accumweight[points->num - 1];

  for (int i = (int)k1; i < k2; i++) {
    w = (lrand48() / (float)INT_MAX) * totalweight;

    l = 0;
    r = (int)points->num - 1;
    if (accumweight[0] > w) {
      (*feasible)[i] = 0;
      continue;
    }
    while (l + 1 < r) {
      k = (l + r) / 2;
      if (accumweight[k] > w) {
        r = k;
      } else {
        l = k;
      }
    }
    (*feasible)[i] = r;
  }

  free(accumweight);

#ifdef PROFILE
  double t2 = gettime();
  time_select_feasible += t2 - t1;
#endif
  return numfeasible;
}

float pkmedian(Points *points, long kmin, long kmax, long* kfinal) {
  int i;
  float cost;
  float lastcost;
  float hiz, loz, z;

  static long k;
  static int *feasible;
  static int numfeasible;

  hiz = loz = 0.0;
  long numberOfPoints = points->num;
  long ptDimension = points->dim;

  float myhiz = 0;
  for (long kk = 0; kk < points->num; kk++) {
    myhiz += dist(points->p[kk], points->p[0], ptDimension) * points->p[kk].weight;
  }
  hiz = myhiz;

  loz = 0.0;
  z = (hiz + loz) / 2.0;

  if (points->num <= kmax) {
    for (long kk = 0; kk < points->num; kk++) {
      points->p[kk].assign = kk;
      points->p[kk].cost = 0;
    }
    cost = 0;
    *kfinal = k;
    return cost;
  }

  shuffle(points);
  cost = pspeedy(points, z, &k);

  i = 0;
  while ((k < kmin) && (i < SP)) {
    cost = pspeedy(points, z, &k);
    i++;
  }

  while (k < kmin) {
    if (i >= SP) {
      hiz = z;
      z = (hiz + loz) / 2.0;
      i = 0;
    }
    shuffle(points);
    cost = pspeedy(points, z, &k);
    i++;
  }

  numfeasible = selectfeasible_fast(points, &feasible, (int)kmin);
  for (int i2 = 0; i2 < points->num; i2++) {
    is_center[points->p[i2].assign] = true;
  }

  while (1) {
    lastcost = cost;
    cost = pFL(points, feasible, numfeasible,
               z, &k, (int)kmax, cost, (long)(ITER * kmax * log((float)kmax)), 0.1f);

    if (((k <= (1.1) * kmax) && (k >= (0.9) * kmin)) ||
        ((k <= kmax + 2) && (k >= kmin - 2))) {
      cost = pFL(points, feasible, numfeasible,
                 z, &k, (int)kmax, cost, (long)(ITER * kmax * log((float)kmax)), 0.001f);
    }

    if (k > kmax) {
      loz = z;
      z = (hiz + loz) / 2.0;
      cost += (z - loz) * k;
    }
    if (k < kmin) {
      hiz = z;
      z = (hiz + loz) / 2.0;
      cost += (z - hiz) * k;
    }

    if (((k <= kmax) && (k >= kmin)) || ((loz >= (0.999) * hiz))) {
      break;
    }
  }

  free(feasible);
  *kfinal = k;

  return cost;
}

int contcenters(Points *points) {
  long i, ii;
  float relweight;

  for (i = 0; i < points->num; i++) {
    if (points->p[i].assign != i) {
      relweight = points->p[points->p[i].assign].weight + points->p[i].weight;
      relweight = points->p[i].weight / relweight;
      for (ii = 0; ii < points->dim; ii++) {
        points->p[points->p[i].assign].coord[ii] *= 1.0 - relweight;
        points->p[points->p[i].assign].coord[ii] +=
            points->p[i].coord[ii] * relweight;
      }
      points->p[points->p[i].assign].weight += points->p[i].weight;
    }
  }

  return 0;
}

void copycenters(Points *points, Points* centers, long* centerIDs, long offset) {
  long i;
  long k;

  bool *is_a_median = (bool *)calloc((size_t)points->num, sizeof(bool));

  for (i = 0; i < points->num; i++) {
    is_a_median[points->p[i].assign] = 1;
  }

  k = centers->num;

  for (i = 0; i < points->num; i++) {
    if (is_a_median[i]) {
      memcpy(centers->p[k].coord, points->p[i].coord, (size_t)points->dim * sizeof(float));
      centers->p[k].weight = points->p[i].weight;
      centerIDs[k] = i + offset;
      k++;
    }
  }

  centers->num = k;

  free(is_a_median);
}

void localSearch(Points* points, long kmin, long kmax, long* kfinal) {
#ifdef PROFILE
  double t1 = gettime();
#endif

  pkmedian(points, kmin, kmax, kfinal);

#ifdef PROFILE
  double t2 = gettime();
  time_local_search += t2 - t1;
#endif
}

void outcenterIDs(Points* centers, long* centerIDs, char* outfile) {
  FILE* fp = fopen(outfile, "w");
  if (fp == NULL) {
    fprintf(stderr, "error opening %s\n", outfile);
    exit(1);
  }
  int* is_a_median = (int*)calloc(sizeof(int), centers->num);
  for (int i = 0; i < centers->num; i++) {
    is_a_median[centers->p[i].assign] = 1;
  }

  for (int i = 0; i < centers->num; i++) {
    if (is_a_median[i]) {
      fprintf(fp, "%u\n", (unsigned)centerIDs[i]);
      fprintf(fp, "%lf\n", centers->p[i].weight);
      for (int k = 0; k < centers->dim; k++) {
        fprintf(fp, "%lf ", centers->p[i].coord[k]);
      }
      fprintf(fp, "\n\n");
    }
  }
  fclose(fp);
  free(is_a_median);
}

void streamCluster(PStream* stream,
                   long kmin, long kmax, int dim,
                   long chunksize, long centersize, char* outfile) {
  float* block = (float*)malloc((size_t)chunksize * dim * sizeof(float));
  float* centerBlock = (float*)malloc((size_t)centersize * dim * sizeof(float));
  long* centerIDs = (long*)malloc((size_t)centersize * dim * sizeof(long));

  if (block == NULL) {
    fprintf(stderr, "not enough memory for a chunk!\n");
    exit(1);
  }

  Points points;
  points.dim = dim;
  points.num = chunksize;
  points.p = (Point *)malloc((size_t)chunksize * sizeof(Point));
  for (int i = 0; i < chunksize; i++) {
    points.p[i].coord = &block[i * dim];
  }

  Points centers;
  centers.dim = dim;
  centers.p = (Point *)malloc((size_t)centersize * sizeof(Point));
  centers.num = 0;

  for (int i = 0; i < centersize; i++) {
    centers.p[i].coord = &centerBlock[i * dim];
    centers.p[i].weight = 1.0;
  }

  long IDoffset = 0;
  long kfinal;
  while (1) {
    size_t numRead = stream->read(block, dim, (int)chunksize);
    fprintf(stderr, "read %d points\n", (int)numRead);

    if (stream->ferror() || (numRead < (unsigned int)chunksize && !stream->feof())) {
      fprintf(stderr, "error reading data!\n");
      exit(1);
    }

    points.num = (long)numRead;
    for (int i = 0; i < points.num; i++) {
      points.p[i].weight = 1.0;
    }

    switch_membership = (bool*)malloc((size_t)points.num * sizeof(bool));
    is_center = (bool*)calloc((size_t)points.num, sizeof(bool));
    center_table = (int*)malloc((size_t)points.num * sizeof(int));

    localSearch(&points, kmin, kmax, &kfinal);

    fprintf(stderr, "finish local search\n");

    contcenters(&points);
    isCoordChanged = true;

    if (kfinal + centers.num > centersize) {
      fprintf(stderr, "oops! no more space for centers\n");
      exit(1);
    }

    copycenters(&points, &centers, centerIDs, IDoffset);
    IDoffset += (long)numRead;

    free(is_center);
    free(switch_membership);
    free(center_table);

    if (stream->feof()) {
      break;
    }
  }

  switch_membership = (bool*)malloc((size_t)centers.num * sizeof(bool));
  is_center = (bool*)calloc((size_t)centers.num, sizeof(bool));
  center_table = (int*)malloc((size_t)centers.num * sizeof(int));

  localSearch(&centers, kmin, kmax, &kfinal);
  contcenters(&centers);
  outcenterIDs(&centers, centerIDs, outfile);

  free(is_center);
  free(switch_membership);
  free(center_table);
  free(points.p);
  free(centers.p);
  free(block);
  free(centerBlock);
  free(centerIDs);
}

int main(int argc, char **argv) {
  char *outfilename = new char[MAXNAMESIZE];
  char *infilename = new char[MAXNAMESIZE];
  long kmin, kmax, n, chunksize, clustersize;
  int dim;
#ifdef PARSEC_VERSION
#define __PARSEC_STRING(x) #x
#define __PARSEC_XSTRING(x) __PARSEC_STRING(x)
  printf("PARSEC Benchmark Suite Version " __PARSEC_XSTRING(PARSEC_VERSION) "\n");
  fflush(NULL);
#else
  printf("PARSEC Benchmark Suite\n");
  fflush(NULL);
#endif
#ifdef ENABLE_PARSEC_HOOKS
  __parsec_bench_begin(__parsec_streamcluster);
#endif

  if (argc < 10) {
    fprintf(stderr, "usage: %s k1 k2 d n chunksize clustersize infile outfile nproc\n",
            argv[0]);
    fprintf(stderr, "  k1:          Min. number of centers allowed\n");
    fprintf(stderr, "  k2:          Max. number of centers allowed\n");
    fprintf(stderr, "  d:           Dimension of each data point\n");
    fprintf(stderr, "  n:           Number of data points\n");
    fprintf(stderr, "  chunksize:   Number of data points to handle per step\n");
    fprintf(stderr, "  clustersize: Maximum number of intermediate centers\n");
    fprintf(stderr, "  infile:      Input file (if n<=0)\n");
    fprintf(stderr, "  outfile:     Output file\n");
    fprintf(stderr, "  nproc:       Number of threads to use\n");
    fprintf(stderr, "\n");
    fprintf(stderr, "if n > 0, points will be randomly generated instead of reading from infile.\n");
    exit(1);
  }
  kmin = atoi(argv[1]);
  kmax = atoi(argv[2]);
  dim = atoi(argv[3]);
  n = atoi(argv[4]);
  chunksize = atoi(argv[5]);
  clustersize = atoi(argv[6]);
  strcpy(infilename, argv[7]);
  strcpy(outfilename, argv[8]);
  nproc = atoi(argv[9]);

  if (nproc < 1) nproc = 1;
  omp_set_num_threads(nproc);

  srand48(SEED);
  PStream* stream;
  if (n > 0) {
    stream = new SimStream(n);
  } else {
    stream = new FileStream(infilename);
  }

  double t1 = gettime();

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_roi_begin();
#endif

  serial_t = 0.0;
  cpu_to_gpu_t = 0.0;
  gpu_to_cpu_t = 0.0;
  alloc_t = 0.0;
  free_t = 0.0;
  kernel_t = 0.0;

  isCoordChanged = false;

  streamCluster(stream, kmin, kmax, dim, chunksize, clustersize, outfilename);

  freeDevMem();
  freeHostMem();

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_roi_end();
#endif

  double t2 = gettime();

  printf("time = %lfs\n", t2 - t1);

  delete stream;
  delete[] outfilename;
  delete[] infilename;

#ifdef PROFILE
  printf("time pgain = %lfs\n", time_gain);
  printf("time pgain_dist = %lfs\n", time_gain_dist);
  printf("time pgain_init = %lfs\n", time_gain_init);
  printf("time pselect = %lfs\n", time_select_feasible);
  printf("time pspeedy = %lfs\n", time_speedy);
  printf("time pshuffle = %lfs\n", time_shuffle);
  printf("time localSearch = %lfs\n", time_local_search);
  printf("\n\n");
  printf("====CUDA Timing info (pgain)====\n");
  printf("time serial = %lfs\n", serial_t / 1000);
  printf("time CPU to GPU memory copy = %lfs\n", cpu_to_gpu_t / 1000);
  printf("time GPU to CPU memory copy back = %lfs\n", gpu_to_cpu_t / 1000);
  printf("time GPU malloc = %lfs\n", alloc_t / 1000);
  printf("time GPU free = %lfs\n", free_t / 1000);
  printf("time kernel = %lfs\n", kernel_t / 1000);
#endif

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_bench_end();
#endif

  return 0;
}

#include <stdio.h>
#include <iostream>
#include <fstream>
#include <stdlib.h>
#include <sys/time.h>
#include <string.h>
#include <assert.h>
#include <math.h>
#include <sys/resource.h>
#include <limits.h>
#include <omp.h>

#ifdef ENABLE_PARSEC_HOOKS
#include <hooks.h>
#endif

using namespace std;

#define MAXNAMESIZE 1024
#define SEED 1
#define SP 1
#define ITER 3

#define PROFILE

typedef struct {
  float weight;
  float *coord;
  long assign;
  float cost;
} Point;

typedef struct {
  long num;
  int dim;
  Point *p;
} Points;

class PStream {
public:
  virtual size_t read(float* dest, int dim, int num) = 0;
  virtual int ferror() = 0;
  virtual int feof() = 0;
  virtual ~PStream() {
  }
};

class SimStream : public PStream {
public:
  SimStream(long n_) {
    n = n_;
  }
  size_t read(float* dest, int dim, int num) {
    size_t count = 0;
    for (int i = 0; i < num && n > 0; i++) {
      for (int k = 0; k < dim; k++) {
        dest[i * dim + k] = lrand48() / (float)INT_MAX;
      }
      n--;
      count++;
    }
    return count;
  }
  int ferror() {
    return 0;
  }
  int feof() {
    return n <= 0;
  }
  ~SimStream() {
  }
private:
  long n;
};

class FileStream : public PStream {
public:
  FileStream(char* filename) {
    fp = fopen(filename, "rb");
    if (fp == NULL) {
      fprintf(stderr, "error opening file %s\n.", filename);
      exit(1);
    }
  }
  size_t read(float* dest, int dim, int num) {
    return std::fread(dest, sizeof(float) * dim, num, fp);
  }
  int ferror() {
    return std::ferror(fp);
  }
  int feof() {
    return std::feof(fp);
  }
  ~FileStream() {
    printf("closing file stream\n");
    fclose(fp);
  }
private:
  FILE* fp;
};

static bool *switch_membership;
static bool *is_center;
static int  *center_table;
static int nproc;
bool isCoordChanged;

double serial_t;
double cpu_to_gpu_t;
double gpu_to_cpu_t;
double alloc_t;
double kernel_t;
double free_t;

#ifdef PROFILE
double time_local_search = 0.0;
double time_speedy = 0.0;
double time_select_feasible = 0.0;
double time_gain = 0.0;
double time_shuffle = 0.0;
double time_gain_dist = 0.0;
double time_gain_init = 0.0;
#endif

static float *coord_h = NULL;
static size_t coord_h_cap = 0;

static int *center_table_d = NULL;
static bool *switch_membership_d = NULL;
static Point *p_dev = NULL;
static float *coord_d = NULL;

static size_t center_table_cap = 0;
static size_t switch_membership_cap = 0;
static size_t p_cap = 0;
static size_t coord_d_cap = 0;

static int iter = 0;

void inttofile(int data, char *filename) {
  FILE *fp = fopen(filename, "w");
  fprintf(fp, "%d ", data);
  fclose(fp);
}

double gettime() {
  struct timeval t;
  gettimeofday(&t, NULL);
  return t.tv_sec + t.tv_usec * 1e-6;
}

int isIdentical(float *i, float *j, int D) {
  int a = 0;
  int equal = 1;
  while (equal && a < D) {
    if (i[a] != j[a]) equal = 0;
    else a++;
  }
  if (equal) return 1;
  else return 0;
}

static int floatcomp(const void *i, const void *j) {
  float a, b;
  a = *(float *)(i);
  b = *(float *)(j);
  if (a > b) return (1);
  if (a < b) return (-1);
  return (0);
}

void allocHostMem(int num, int dim) {
  size_t need = (size_t)num * (size_t)dim;
  if (need > coord_h_cap) {
    free(coord_h);
    coord_h = (float*)malloc(need * sizeof(float));
    coord_h_cap = need;
  }
}

void allocDevMem(int num, int dim) {
  size_t n = (size_t)num;
  size_t coord_need = (size_t)num * (size_t)dim;

  if (n > center_table_cap) {
    free(center_table_d);
    center_table_d = (int*)malloc(n * sizeof(int));
    center_table_cap = n;
  }
  if (n > switch_membership_cap) {
    free(switch_membership_d);
    switch_membership_d = (bool*)malloc(n * sizeof(bool));
    switch_membership_cap = n;
  }
  if (n > p_cap) {
    free(p_dev);
    p_dev = (Point*)malloc(n * sizeof(Point));
    p_cap = n;
  }
  if (coord_need > coord_d_cap) {
    free(coord_d);
    coord_d = (float*)malloc(coord_need * sizeof(float));
    coord_d_cap = coord_need;
  }
}

void freeDevMem() {
  free(center_table_d);
  free(switch_membership_d);
  free(p_dev);
  free(coord_d);
  center_table_d = NULL;
  switch_membership_d = NULL;
  p_dev = NULL;
  coord_d = NULL;
  center_table_cap = 0;
  switch_membership_cap = 0;
  p_cap = 0;
  coord_d_cap = 0;
}

void freeHostMem() {
  free(coord_h);
  coord_h = NULL;
  coord_h_cap = 0;
}

void shuffle(Points *points) {
#ifdef PROFILE
  double t1 = gettime();
#endif
  long i, j;
  Point temp;
  for (i = 0; i < points->num - 1; i++) {
    j = (lrand48() % (points->num - i)) + i;
    temp = points->p[i];
    points->p[i] = points->p[j];
    points->p[j] = temp;
  }
#ifdef PROFILE
  double t2 = gettime();
  time_shuffle += t2 - t1;
#endif
}

void intshuffle(int *intarray, int length) {
#ifdef PROFILE
  double t1 = gettime();
#endif
  long i, j;
  int temp;
  for (i = 0; i < length; i++) {
    j = (lrand48() % (length - i)) + i;
    temp = intarray[i];
    intarray[i] = intarray[j];
    intarray[j] = temp;
  }
#ifdef PROFILE
  double t2 = gettime();
  time_shuffle += t2 - t1;
#endif
}

float dist(Point p1, Point p2, int dim) {
  int i;
  float result = 0.0;
  for (i = 0; i < dim; i++)
    result += (p1.coord[i] - p2.coord[i]) * (p1.coord[i] - p2.coord[i]);
  return result;
}

static inline float d_dist(int p1i, int p2i, int num, int dim, float *coord_arr) {
  float retval = 0.0f;
  for (int i = 0; i < dim; i++) {
    float tmp = coord_arr[(size_t)i * (size_t)num + (size_t)p1i] -
                coord_arr[(size_t)i * (size_t)num + (size_t)p2i];
    retval += tmp * tmp;
  }
  return retval;
}

float pgain(long x, Points *points, float z, long int *numcenters, int kmax,
            bool *is_center_arr, int *center_table_arr, bool *switch_membership_arr,
            bool isCoordChangedLocal, double *serial_t_ptr, double *cpu_to_gpu_t_ptr,
            double *gpu_to_cpu_t_ptr, double *alloc_t_ptr, double *kernel_t_ptr,
            double *free_t_ptr) {
#ifdef PROFILE
  double gain_t1 = gettime();
  double init_t1 = gettime();
#endif

  double t0 = gettime();

  int stride = (int)(*numcenters) + 1;
  int K = (int)(*numcenters);
  int num = (int)points->num;
  int dim = points->dim;
  int nThread = num;

  float *work_mem_h = (float*)malloc((size_t)stride * (size_t)(nThread + 1) * sizeof(float));

  allocHostMem(num, dim);

  int count = 0;
  for (int i = 0; i < num; i++) {
    if (is_center_arr[i]) {
      center_table_arr[i] = count++;
    }
  }

  if (isCoordChangedLocal || iter == 0) {
    for (int i = 0; i < dim; i++) {
      for (int j = 0; j < num; j++) {
        coord_h[(size_t)num * (size_t)i + (size_t)j] = points->p[j].coord[i];
      }
    }
  }

  *serial_t_ptr += (gettime() - t0) * 1000.0;

  t0 = gettime();
  allocDevMem(num, dim);
  *alloc_t_ptr += (gettime() - t0) * 1000.0;

  t0 = gettime();
  if (isCoordChangedLocal || iter == 0) {
    memcpy(coord_d, coord_h, (size_t)num * (size_t)dim * sizeof(float));
  }
  memcpy(center_table_d, center_table_arr, (size_t)num * sizeof(int));
  memcpy(p_dev, points->p, (size_t)num * sizeof(Point));

  memset((void*)switch_membership_arr, 0, (size_t)num * sizeof(bool));
  memset((void*)work_mem_h, 0, (size_t)stride * (size_t)(nThread + 1) * sizeof(float));
  *cpu_to_gpu_t_ptr += (gettime() - t0) * 1000.0;

#ifdef PROFILE
  time_gain_init += gettime() - init_t1;
  double dist_t1 = gettime();
#endif

  t0 = gettime();
#pragma omp parallel for schedule(static)
  for (int tid = 0; tid < num; tid++) {
    float *lower = &work_mem_h[(size_t)tid * (size_t)stride];
    float x_cost = d_dist(tid, (int)x, num, dim, coord_d) * p_dev[tid].weight;

    if (x_cost < p_dev[tid].cost) {
      switch_membership_arr[tid] = 1;
      lower[K] += x_cost - p_dev[tid].cost;
    } else {
      lower[center_table_d[p_dev[tid].assign]] += p_dev[tid].cost - x_cost;
    }
  }
  *kernel_t_ptr += (gettime() - t0) * 1000.0;

#ifdef PROFILE
  time_gain_dist += gettime() - dist_t1;
#endif

  t0 = gettime();
  *gpu_to_cpu_t_ptr += (gettime() - t0) * 1000.0;

  t0 = gettime();

  int number_of_centers_to_close = 0;
  float gl_cost_of_opening_x = z;
  float *gl_lower = &work_mem_h[(size_t)stride * (size_t)nThread];

  for (int i = 0; i < num; i++) {
    if (is_center_arr[i]) {
      float low = z;
      for (int j = 0; j < num; j++) {
        low += work_mem_h[(size_t)j * (size_t)stride + (size_t)center_table_arr[i]];
      }

      gl_lower[center_table_arr[i]] = low;

      if (low > 0) {
        ++number_of_centers_to_close;
        work_mem_h[(size_t)i * (size_t)stride + (size_t)K] -= low;
      }
    }
    gl_cost_of_opening_x += work_mem_h[(size_t)i * (size_t)stride + (size_t)K];
  }

  if (gl_cost_of_opening_x < 0) {
    for (int i = 0; i < num; i++) {
      bool close_center = gl_lower[center_table_arr[points->p[i].assign]] > 0;
      if (switch_membership_arr[i] || close_center) {
        points->p[i].cost = dist(points->p[i], points->p[x], dim) * points->p[i].weight;
        points->p[i].assign = x;
      }
    }

    for (int i = 0; i < num; i++) {
      if (is_center_arr[i] && gl_lower[center_table_arr[i]] > 0) {
        is_center_arr[i] = false;
      }
    }

    if (x >= 0 && x < num) {
      is_center_arr[x] = true;
    }
    *numcenters = *numcenters + 1 - number_of_centers_to_close;
  } else {
    gl_cost_of_opening_x = 0;
  }

  free(work_mem_h);
  *serial_t_ptr += (gettime() - t0) * 1000.0;

  t0 = gettime();
  *free_t_ptr += (gettime() - t0) * 1000.0;

  iter++;

#ifdef PROFILE
  time_gain += gettime() - gain_t1;
#endif
  return -gl_cost_of_opening_x;
}

float pspeedy(Points *points, float z, long *kcenter) {
#ifdef PROFILE
  double t1 = gettime();
#endif

  long numberOfPoints = points->num;
  int dim = points->dim;

#pragma omp parallel for schedule(static)
  for (long k = 0; k < numberOfPoints; k++) {
    float distance = dist(points->p[k], points->p[0], dim);
    points->p[k].cost = distance * points->p[k].weight;
    points->p[k].assign = 0;
  }

  *kcenter = 1;

  for (long i = 1; i < numberOfPoints; i++) {
    bool to_open = ((float)lrand48() / (float)INT_MAX) < (points->p[i].cost / z);
    if (to_open) {
      (*kcenter)++;
#pragma omp parallel for schedule(static)
      for (long k = 0; k < numberOfPoints; k++) {
        float distance = dist(points->p[i], points->p[k], dim);
        if (distance * points->p[k].weight < points->p[k].cost) {
          points->p[k].cost = distance * points->p[k].weight;
          points->p[k].assign = i;
        }
      }
    }
  }

  float totalcost = z * (*kcenter);
#pragma omp parallel for reduction(+:totalcost) schedule(static)
  for (long k = 0; k < numberOfPoints; k++) {
    totalcost += points->p[k].cost;
  }

#ifdef PROFILE
  double t2 = gettime();
  time_speedy += t2 - t1;
#endif
  return totalcost;
}

float pFL(Points *points, int *feasible, int numfeasible,
          float z, long *k, int kmax, float cost, long iterCount, float e) {
  long i;
  long x;
  float change;
  long numberOfPoints;

  change = cost;

  while (change / cost > 1.0 * e) {
    change = 0.0;
    numberOfPoints = points->num;

    intshuffle(feasible, numfeasible);

    for (i = 0; i < iterCount; i++) {
      x = i % numfeasible;
      change += pgain(feasible[x], points, z, k, kmax, is_center, center_table,
                      switch_membership, isCoordChanged,
                      &serial_t, &cpu_to_gpu_t, &gpu_to_cpu_t,
                      &alloc_t, &kernel_t, &free_t);
    }

    cost -= change;
#ifdef PRINTINFO
    fprintf(stderr, "%ld centers, cost %lf, total distance %lf\n",
            *k, cost, cost - z * (*k));
#endif
  }
  return cost;
}

int selectfeasible_fast(Points *points, int **feasible, int kmin) {
#ifdef PROFILE
  double t1 = gettime();
#endif

  int numfeasible = (int)points->num;
  if (numfeasible > (ITER * kmin * log((float)kmin)))
    numfeasible = (int)(ITER * kmin * log((float)kmin));
  *feasible = (int *)malloc((size_t)numfeasible * sizeof(int));

  float* accumweight;
  float totalweight;

  long k1 = 0;
  long k2 = numfeasible;

  float w;
  int l, r, k;

  if (numfeasible == points->num) {
    for (int i = (int)k1; i < (int)k2; i++)
      (*feasible)[i] = i;
    return numfeasible;
  }

  accumweight = (float*)malloc((size_t)points->num * sizeof(float));
  accumweight[0] = points->p[0].weight;
  totalweight = 0;
  for (int i = 1; i < points->num; i++) {
    accumweight[i] = accumweight[i - 1] + points->p[i].weight;
  }
  totalweight = accumweight[points->num - 1];

  for (int i = (int)k1; i < (int)k2; i++) {
    w = (lrand48() / (float)INT_MAX) * totalweight;

    l = 0;
    r = (int)points->num - 1;
    if (accumweight[0] > w) {
      (*feasible)[i] = 0;
      continue;
    }
    while (l + 1 < r) {
      k = (l + r) / 2;
      if (accumweight[k] > w) {
        r = k;
      } else {
        l = k;
      }
    }
    (*feasible)[i] = r;
  }

  free(accumweight);

#ifdef PROFILE
  double t2 = gettime();
  time_select_feasible += t2 - t1;
#endif
  return numfeasible;
}

float pkmedian(Points *points, long kmin, long kmax, long* kfinal) {
  int i;
  float cost;
  float lastcost;
  float hiz, loz, z;

  static long k;
  int *feasible = NULL;
  int numfeasible = 0;

  hiz = loz = 0.0;
  long numberOfPoints = points->num;
  long ptDimension = points->dim;

#ifdef PRINTINFO
  printf("Starting Kmedian procedure\n");
  printf("%li points in %li dimensions\n", numberOfPoints, ptDimension);
#endif

#pragma omp parallel for reduction(+:hiz) schedule(static)
  for (long kk = 0; kk < points->num; kk++) {
    hiz += dist(points->p[kk], points->p[0], ptDimension) * points->p[kk].weight;
  }

  loz = 0.0;
  z = (hiz + loz) / 2.0;

  if (points->num <= kmax) {
#pragma omp parallel for schedule(static)
    for (long kk = 0; kk < points->num; kk++) {
      points->p[kk].assign = kk;
      points->p[kk].cost = 0;
    }
    cost = 0;
    *kfinal = k;
    return cost;
  }

  shuffle(points);
  cost = pspeedy(points, z, &k);

#ifdef PRINTINFO
  printf("Finished first call to speedy, cost=%lf, k=%li\n", cost, k);
#endif
  i = 0;

  while ((k < kmin) && (i < SP)) {
    cost = pspeedy(points, z, &k);
    i++;
  }

#ifdef PRINTINFO
  printf("second call to speedy, cost=%lf, k=%li\n", cost, k);
#endif

  while (k < kmin) {
#ifdef PRINTINFO
    printf("%lf %lf\n", loz, hiz);
    printf("Speedy indicates we should try lower z\n");
#endif
    if (i >= SP) {
      hiz = z;
      z = (hiz + loz) / 2.0;
      i = 0;
    }
    shuffle(points);
    cost = pspeedy(points, z, &k);
    i++;
  }

  numfeasible = selectfeasible_fast(points, &feasible, (int)kmin);
  for (int ii = 0; ii < points->num; ii++) {
    is_center[points->p[ii].assign] = true;
  }

  while (1) {
#ifdef PRINTINFO
    printf("loz = %lf, hiz = %lf\n", loz, hiz);
    printf("Running Local Search...\n");
#endif

    lastcost = cost;
    (void)lastcost;
    cost = pFL(points, feasible, numfeasible, z, &k, (int)kmax, cost,
               (long)(ITER * kmax * log((float)kmax)), 0.1f);

    if (((k <= (1.1) * kmax) && (k >= (0.9) * kmin)) ||
        ((k <= kmax + 2) && (k >= kmin - 2))) {
#ifdef PRINTINFO
      printf("Trying a more accurate local search...\n");
#endif
      cost = pFL(points, feasible, numfeasible, z, &k, (int)kmax, cost,
                 (long)(ITER * kmax * log((float)kmax)), 0.001f);
    }

    if (k > kmax) {
      loz = z;
      z = (hiz + loz) / 2.0;
      cost += (z - loz) * k;
    }
    if (k < kmin) {
      hiz = z;
      z = (hiz + loz) / 2.0;
      cost += (z - hiz) * k;
    }

    if (((k <= kmax) && (k >= kmin)) || ((loz >= (0.999) * hiz))) {
      break;
    }
  }

  free(feasible);
  *kfinal = k;

  return cost;
}

int contcenters(Points *points) {
  long i, ii;
  float relweight;

  for (i = 0; i < points->num; i++) {
    if (points->p[i].assign != i) {
      relweight = points->p[points->p[i].assign].weight + points->p[i].weight;
      relweight = points->p[i].weight / relweight;
      for (ii = 0; ii < points->dim; ii++) {
        points->p[points->p[i].assign].coord[ii] *= 1.0 - relweight;
        points->p[points->p[i].assign].coord[ii] +=
            points->p[i].coord[ii] * relweight;
      }
      points->p[points->p[i].assign].weight += points->p[i].weight;
    }
  }

  return 0;
}

void copycenters(Points *points, Points* centers, long* centerIDs, long offset) {
  long i;
  long k;

  bool *is_a_median = (bool *)calloc((size_t)points->num, sizeof(bool));

  for (i = 0; i < points->num; i++) {
    is_a_median[points->p[i].assign] = 1;
  }

  k = centers->num;

  for (i = 0; i < points->num; i++) {
    if (is_a_median[i]) {
      memcpy(centers->p[k].coord, points->p[i].coord,
             (size_t)points->dim * sizeof(float));
      centers->p[k].weight = points->p[i].weight;
      centerIDs[k] = i + offset;
      k++;
    }
  }

  centers->num = k;

  free(is_a_median);
}

void localSearch(Points* points, long kmin, long kmax, long* kfinal) {
#ifdef PROFILE
  double t1 = gettime();
#endif

  omp_set_dynamic(0);
  omp_set_num_threads(nproc);
  pkmedian(points, kmin, kmax, kfinal);

#ifdef PROFILE
  double t2 = gettime();
  time_local_search += t2 - t1;
#endif
}

void outcenterIDs(Points* centers, long* centerIDs, char* outfile) {
  FILE* fp = fopen(outfile, "w");
  if (fp == NULL) {
    fprintf(stderr, "error opening %s\n", outfile);
    exit(1);
  }
  int* is_a_median = (int*)calloc(sizeof(int), centers->num);
  for (int i = 0; i < centers->num; i++) {
    is_a_median[centers->p[i].assign] = 1;
  }

  for (int i = 0; i < centers->num; i++) {
    if (is_a_median[i]) {
      fprintf(fp, "%u\n", (unsigned)centerIDs[i]);
      fprintf(fp, "%lf\n", centers->p[i].weight);
      for (int k = 0; k < centers->dim; k++) {
        fprintf(fp, "%lf ", centers->p[i].coord[k]);
      }
      fprintf(fp, "\n\n");
    }
  }
  fclose(fp);
  free(is_a_median);
}

void streamCluster(PStream* stream,
                   long kmin, long kmax, int dim,
                   long chunksize, long centersize, char* outfile) {
  float* block = (float*)malloc((size_t)chunksize * (size_t)dim * sizeof(float));
  float* centerBlock = (float*)malloc((size_t)centersize * (size_t)dim * sizeof(float));
  long* centerIDs = (long*)malloc((size_t)centersize * (size_t)dim * sizeof(long));

  if (block == NULL) {
    fprintf(stderr, "not enough memory for a chunk!\n");
    exit(1);
  }

  Points points;
  points.dim = dim;
  points.num = chunksize;
  points.p = (Point *)malloc((size_t)chunksize * sizeof(Point));
  for (int i = 0; i < chunksize; i++) {
    points.p[i].coord = &block[(size_t)i * (size_t)dim];
  }

  Points centers;
  centers.dim = dim;
  centers.p = (Point *)malloc((size_t)centersize * sizeof(Point));
  centers.num = 0;

  for (int i = 0; i < centersize; i++) {
    centers.p[i].coord = &centerBlock[(size_t)i * (size_t)dim];
    centers.p[i].weight = 1.0;
  }

  long IDoffset = 0;
  long kfinal;
  while (1) {
    size_t numRead = stream->read(block, dim, (int)chunksize);
    fprintf(stderr, "read %d points\n", (int)numRead);

    if (stream->ferror() || (numRead < (unsigned int)chunksize && !stream->feof())) {
      fprintf(stderr, "error reading data!\n");
      exit(1);
    }

    points.num = (long)numRead;
    for (int i = 0; i < points.num; i++) {
      points.p[i].weight = 1.0;
    }

    switch_membership = (bool*)malloc((size_t)points.num * sizeof(bool));
    is_center = (bool*)calloc((size_t)points.num, sizeof(bool));
    center_table = (int*)malloc((size_t)points.num * sizeof(int));

    localSearch(&points, kmin, kmax, &kfinal);

    fprintf(stderr, "finish local search\n");

    contcenters(&points);
    isCoordChanged = true;

    if (kfinal + centers.num > centersize) {
      fprintf(stderr, "oops! no more space for centers\n");
      exit(1);
    }

    copycenters(&points, &centers, centerIDs, IDoffset);
    IDoffset += (long)numRead;

    free(is_center);
    free(switch_membership);
    free(center_table);

    if (stream->feof()) {
      break;
    }
  }

  switch_membership = (bool*)malloc((size_t)centers.num * sizeof(bool));
  is_center = (bool*)calloc((size_t)centers.num, sizeof(bool));
  center_table = (int*)malloc((size_t)centers.num * sizeof(int));

  localSearch(&centers, kmin, kmax, &kfinal);
  contcenters(&centers);
  outcenterIDs(&centers, centerIDs, outfile);

  free(is_center);
  free(switch_membership);
  free(center_table);
  free(points.p);
  free(centers.p);
  free(block);
  free(centerBlock);
  free(centerIDs);
}

int main(int argc, char **argv) {
  char *outfilename = new char[MAXNAMESIZE];
  char *infilename = new char[MAXNAMESIZE];
  long kmin, kmax, n, chunksize, clustersize;
  int dim;
#ifdef PARSEC_VERSION
#define __PARSEC_STRING(x) #x
#define __PARSEC_XSTRING(x) __PARSEC_STRING(x)
  printf("PARSEC Benchmark Suite Version " __PARSEC_XSTRING(PARSEC_VERSION) "\n");
  fflush(NULL);
#else
  printf("PARSEC Benchmark Suite\n");
  fflush(NULL);
#endif
#ifdef ENABLE_PARSEC_HOOKS
  __parsec_bench_begin(__parsec_streamcluster);
#endif

  if (argc < 10) {
    fprintf(stderr, "usage: %s k1 k2 d n chunksize clustersize infile outfile nproc\n",
            argv[0]);
    fprintf(stderr, "  k1:          Min. number of centers allowed\n");
    fprintf(stderr, "  k2:          Max. number of centers allowed\n");
    fprintf(stderr, "  d:           Dimension of each data point\n");
    fprintf(stderr, "  n:           Number of data points\n");
    fprintf(stderr, "  chunksize:   Number of data points to handle per step\n");
    fprintf(stderr, "  clustersize: Maximum number of intermediate centers\n");
    fprintf(stderr, "  infile:      Input file (if n<=0)\n");
    fprintf(stderr, "  outfile:     Output file\n");
    fprintf(stderr, "  nproc:       Number of threads to use\n");
    fprintf(stderr, "\n");
    fprintf(stderr, "if n > 0, points will be randomly generated instead of reading from infile.\n");
    exit(1);
  }
  kmin = atoi(argv[1]);
  kmax = atoi(argv[2]);
  dim = atoi(argv[3]);
  n = atol(argv[4]);
  chunksize = atol(argv[5]);
  clustersize = atol(argv[6]);
  strcpy(infilename, argv[7]);
  strcpy(outfilename, argv[8]);
  nproc = atoi(argv[9]);

  srand48(SEED);
  PStream* stream;
  if (n > 0) {
    stream = new SimStream(n);
  } else {
    stream = new FileStream(infilename);
  }

  double t1 = gettime();

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_roi_begin();
#endif

  serial_t = 0.0;
  cpu_to_gpu_t = 0.0;
  gpu_to_cpu_t = 0.0;
  alloc_t = 0.0;
  free_t = 0.0;
  kernel_t = 0.0;

  isCoordChanged = false;

  streamCluster(stream, kmin, kmax, dim, chunksize, clustersize, outfilename);

  freeDevMem();
  freeHostMem();

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_roi_end();
#endif

  double t2 = gettime();

  printf("time = %lfs\n", t2 - t1);

  delete stream;
  delete[] outfilename;
  delete[] infilename;

#ifdef PROFILE
  printf("time pgain = %lfs\n", time_gain);
  printf("time pgain_dist = %lfs\n", time_gain_dist);
  printf("time pgain_init = %lfs\n", time_gain_init);
  printf("time pselect = %lfs\n", time_select_feasible);
  printf("time pspeedy = %lfs\n", time_speedy);
  printf("time pshuffle = %lfs\n", time_shuffle);
  printf("time localSearch = %lfs\n", time_local_search);
  printf("\n\n");
  printf("====CUDA Timing info (pgain)====\n");
  printf("time serial = %lfs\n", serial_t / 1000);
  printf("time CPU to GPU memory copy = %lfs\n", cpu_to_gpu_t / 1000);
  printf("time GPU to CPU memory copy back = %lfs\n", gpu_to_cpu_t / 1000);
  printf("time GPU malloc = %lfs\n", alloc_t / 1000);
  printf("time GPU free = %lfs\n", free_t / 1000);
  printf("time kernel = %lfs\n", kernel_t / 1000);
#endif

#ifdef ENABLE_PARSEC_HOOKS
  __parsec_bench_end();
#endif

  return 0;
}
